const items = $input.all();

// تحويل البيانات
const output = items.map(item => {
  const leadId = item.json.lead_id || null;
  const contactId = item.json.contact_id || null;
  const originalIndex = item.json._originalIndex != null ? String(item.json._originalIndex) : "unknown";

  return {
    json: {
      id: leadId,
      contact_id: contactId,
      company_id: null, // أو نضيف استخراج لاحقًا لو عندك قيمة
      request_id: [originalIndex],
      merged: false
    }
