});

return output;

const items = $input.all();

return items
  .filter(i => i.json.status === 'not_found')
  .map(i => {
    const data = i.json;
    return {
      json: {
        name: data.name,
        pipeline_id: data.pipeline_id,
        status_id: data.status_id,
        responsible_user_id: data.responsible_user_id,
        tags: data.tags,
        _embedded: {
          contacts: data._embedded.contacts,
          companies: data._embedded.companies
        }
      }
    }
  });

// اجلب كل العناصر المجمعة (contacts + leads) بعد إضافة index
const all = $input.all();

const contacts = all.filter(item => item.json.contact_id !== undefined);
const leads = all.filter(item => item.json.lead_id !== undefined);

const matched = [];

for (const contact of contacts) {
  // ابحث عن lead يطابق في company_id أو في index (أو كليهما)
  const companyIds = contact.json.company_ids || [];
  const idx = contact.json.index;
  let lead = leads.find(l => {
    // تحقق من وجود company_id مطابق
    const leadCompanies = (l.json.companies || []).map(c => c.id);
    const companyMatch = companyIds.length > 0 && leadCompanies.some(id => companyIds.includes(id));
    const indexMatch = l.json.index === idx;
    return companyMatch || indexMatch;
  });

  if (lead) {
    matched.push({
      json: {
        matched: true,
        contact: contact.json,
        lead: lead.json
      }
    });
  } else {
    matched.push({
      json: {
        matched: false,
        contact: contact.json,
        note: "لم يتم العثور على lead مطابق"
      }
    });
  }
}

// إذا تريد دمج leads غير المطابقة أيضاً، يمكن إضافة كود مماثل لهم

return matched;

const items = $input.all();

