const now = new Date();
const isoDate = now.toISOString(); // التاريخ والوقت الحالي بصيغة ISO
const batchLabel = isoDate.split("T")[0]; // فقط التاريخ

function normalize(str) {
  return str
    ?.toUpperCase()
    ?.normalize("NFD")
    ?.replace(/[\u0300-\u036f]/g, "") // إزالة العلامات
    ?.replace(/İ/g, "I")
    ?.replace(/Ş/g, "S")
    ?.replace(/Ğ/g, "G")
    ?.replace(/Ü/g, "U")
    ?.replace(/Ö/g, "O")
    ?.replace(/Ç/g, "C")
    ?.trim();
}

return items.map(item => {
  const name = item.json.companyName || "";
  const message = item.json.message || "";
  const folderId = item.json.folderId || "";
  const documentId = item.json.documentId || "";

  const note = `📦 ملف جديد تم نقله إلى Google Drive\n\n${message}\n\n📁 فولدر ID: ${folderId}\n📄 ملف ID: ${documentId}\n⏰ تاريخ التصدير: ${batchLabel}`;

  return {
    json: {
      ...item.json,
      normalized_company: normalize(name),
      export_date: isoDate,
      kommo_note: note
    }
  };
});

function cleanPhone(raw) {
  if (!raw) return "";
  return raw.replace(/[^+\d]/g, "");
}

return $input.all().map(item => {
  // output Kommo موجود في data كنص JSON
  let data = typeof item.json.data === "string" ? JSON.parse(item.json.data) : item.json.data;
  let contacts = data?._embedded?.contacts || [];
  // لو لم يوجد أي contact يرجع عنصر فارغ مع found = false
  if (contacts.length === 0) {
    return {
      json: {
        found: false,
        message: "No contact found in Kommo for this query.",
      }
    }
  }

  // لو فيه أكثر من contact يرجعهم كلهم (واحد واحد)
  return contacts.map(contact => {
    // استخراج أرقام الهاتف والإيميل (قد يوجد أكثر من واحد)
    let phones = [];
    let emails = [];
    let pipeline_id = null;
    let status_id = null;
    let lead_id = null;
    let company_ids = [];
    let tags = [];

    // حقول مخصصة
    if (Array.isArray(contact.custom_fields_values)) {
      for (const f of contact.custom_fields_values) {
        if (f.field_code === "PHONE" || f.field_name === "Phone") {
          phones.push(...(f.values || []).map(v => cleanPhone(v.value)));
        }
        if (f.field_code === "EMAIL" || f.field_name === "Email") {
          emails.push(...(f.values || []).map(v => v.value));
        }
      }
    }

    // استخراج بيانات الشركات المرتبطة (companies)
    if (contact._embedded?.companies) {
      company_ids = contact._embedded.companies.map(c => c.id);
    }

    // استخراج بيانات التاجز
    if (contact._embedded?.tags) {
      tags = contact._embedded.tags.map(t => t.name || t.id);
    }

    // إذا فيه lead_id أو pipeline_id أو status_id في مكان آخر (مثلاً في الـleads)
    // أضف هنا حسب الحاجة، غالبًا تحتاج طلب إضافي لجلب بيانات lead نفسها

    return {
      json: {
        found: true,
        contact_id: contact.id,
        contact_name: contact.name,
        first_name: contact.first_name,
        last_name: contact.last_name,
        responsible_user_id: contact.responsible_user_id,
        phones,
        emails,
        company_ids,
        tags,
        // أضف المزيد حسب الحاجة
        kommo_raw_contact: contact // كامل بيانات contact من Kommo
      }
    }
  });
}).flat();

return $input.all().map(item => {
