// -------- دوال المساعدة --------

/**
 * تنظيف وتوحيد النص
 */
function normalizeText(text) {
  if (!text) return "";

  let t = String(text)
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();

  // توحيد مسافات ورموز
  t = t.replace(/[_\-–—\.]+/g, " ").replace(/\s+/g, " ").trim();

  // تطبيع الحروف التركية
  const turkishMap = {
    'ı': 'i', 'İ': 'i',
    'ş': 's', 'Ş': 's', 
    'ğ': 'g', 'Ğ': 'g',
    'ç': 'c', 'Ç': 'c',
    'ö': 'o', 'Ö': 'o',
    'ü': 'u', 'Ü': 'u'
  };

  for (const [from, to] of Object.entries(turkishMap)) {
    t = t.replace(new RegExp(from, 'g'), to);
  }

  return t;
}

/**
 * إزالة البادئات الخاصة والحالات القانونية
 */
function cleanSpecialPrefixes(name) {
  let n = normalizeText(name);

  // إزالة حالات التصفية
  const liquidationPatterns = [
    /^tasf\.?\s*hal\.?\s*/i,
    /^tasfiye\s+halinde\s*/i,
    /^tasfiyede\s*/i,
    /^tas\.?\s*hal\.?\s*/i,
  ];

  for (const pattern of liquidationPatterns) {
    n = n.replace(pattern, "").trim();
  }

  // إزالة كلمة TAX من البداية
  n = n.replace(/^tax\s+/i, "").trim();

  return n;
}

/**
 * استخراج اسم الشركة من اسم الملف
 */
function extractCompanyNameFromFileName(fileName) {
  if (!fileName) return "";

  let name = fileName;

  // إزالة امتداد الملف
  name = name.replace(/\.(pdf|xlsx|xls|doc|docx)$/i, "").trim();

  // إزالة التواريخ والأشهر
  const months = [
    "ocak", "şubat", "mart", "nisan", "mayıs", "haziran",
    "temmuz", "ağustos", "eylül", "ekim", "kasım", "aralık",
    "january", "february", "march", "april", "may", "june",
    "july", "august", "september", "october", "november", "december"
  ];

  for (const month of months) {
    const regex = new RegExp(`\\s+${month}\\s+\\d{4}`, "gi");
    name = name.replace(regex, "");
  }

  // إزالة السنوات
  name = name.replace(/\s+\d{4}\s*/g, " ");

  // إزالة أنواع المستندات
  const docTypes = ["kdv", "kdv2", "sgk", "thk", "muhtasar", "muhsgk", "tahakkuk", "beyanname", "hizmet listesi", "vergisi", "emekli", "xml", "aylik"];
  for (const docType of docTypes) {
    const regex = new RegExp(`\\s+${docType}\\b`, "gi");
    name = name.replace(regex, "");
  }

  // إزالة الأرقام والرموز الزائدة
  name = name.replace(/\s+\d+\s*/g, " ");
  name = name.replace(/[_\-–—\(\)]+/g, " ");

  return name.trim();
}

/**
 * إزالة اللواحق من نهاية أسماء الشركات
 */
function stripCompanySuffixes(name) {
  let n = normalizeText(name);

  // إزالة اللواحق بالترتيب من الأطول للأقصر
  const suffixesToRemove = [
    // عبارات طويلة
    "sanayi ticaret anonim sirketi",
    "ic ve dis ticaret limited sirketi",
    "ithalat ve ihracat limited sirketi",
    "ithalat ihracat limited sirketi",
    "ic ve dis ticaret",
    "ithalat ve ihracat",
    "ithalat ihracat",
    "sanayi ticaret",
    "dis ticaret",
    "limited sirketi",
    "anonim sirketi",

    // كلمات مفردة
    "gayrimenkul", "realestate", "realstate",
    "anonim", "limited", "sirketi",
    "ticaret", "sanayi", "ithalat", "ihracat", "lojistik",
    "danismanlik", "hizmet", "yatirim", "yapimi",
    "ltd", "sti", "as", "a.s", "a.s.",

    // كلمات ربط
    "ve", "and"
  ];

  for (const suffix of suffixesToRemove) {
    const pattern = new RegExp(`\\s+${suffix}\\s*$`, 'gi');
    n = n.replace(pattern, "").trim();
  }

  return n.trim();
}

/**
 * حساب مسافة التحرير (Levenshtein Distance)
 */
function editDistance(s1, s2) {
  const len1 = s1.length;
  const len2 = s2.length;

  const matrix = Array(len1 + 1).fill(null).map(() => Array(len2 + 1).fill(0));

  for (let i = 0; i <= len1; i++) matrix[i][0] = i;
  for (let j = 0; j <= len2; j++) matrix[0][j] = j;

  for (let i = 1; i <= len1; i++) {
    for (let j = 1; j <= len2; j++) {
      const cost = s1[i - 1] === s2[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost
      );
    }
  }

  return matrix[len1][len2];
}

/**
 * حساب نسبة التشابه
 */
function similarityScore(s1, s2) {
  const maxLen = Math.max(s1.length, s2.length);
  if (maxLen === 0) return 1.0;

  const distance = editDistance(s1, s2);
  return 1 - (distance / maxLen);
}

/**
 * ✅ التحقق من تطابق الكلمة الأولى (قاعدة الأمان)
 */
function hasFirstWordMatch(name1, name2) {
  const words1 = stripCompanySuffixes(normalizeText(name1)).split(/\s+/).filter(w => w.length > 2);
  const words2 = stripCompanySuffixes(normalizeText(name2)).split(/\s+/).filter(w => w.length > 2);

  if (words1.length === 0 || words2.length === 0) return false;

  // يجب أن تتطابق الكلمة الأولى على الأقل
  return words1[0] === words2[0];
}

/**
 * المطابقة الذكية المحسّنة مع قواعد الأمان
 */
function smartMatch(name1, name2) {
  // تنظيف الأسماء
  const clean1 = cleanSpecialPrefixes(name1);
  const clean2 = cleanSpecialPrefixes(name2);

  // تطبيع كامل
  const norm1 = normalizeText(clean1);
  const norm2 = normalizeText(clean2);

  // إزالة اللواحق
  const stripped1 = stripCompanySuffixes(clean1);
  const stripped2 = stripCompanySuffixes(clean2);

  // 1. تطابق تام
  if (norm1 === norm2 || stripped1 === stripped2) {
    return 1.0;
  }

  // 2. أحدهما يبدأ بالآخر
  if (norm1.startsWith(norm2) || norm2.startsWith(norm1)) {
    return 0.95;
  }
  if (stripped1.startsWith(stripped2) || stripped2.startsWith(stripped1)) {
    return 0.93;
  }

  // 3. أحدهما يحتوي الآخر
  if (norm1.includes(norm2) || norm2.includes(norm1)) {
    return 0.90;
  }
  if (stripped1.includes(stripped2) || stripped2.includes(stripped1)) {
    return 0.88;
  }

  // ✅ قاعدة الأمان: يجب أن تتطابق الكلمة الأولى
  if (!hasFirstWordMatch(name1, name2)) {
    return 0; // رفض المطابقة تماماً
  }

  // 4. مطابقة الكلمات الأساسية
  const words1 = stripped1.split(/\s+/).filter(w => w.length > 2);
  const words2 = stripped2.split(/\s+/).filter(w => w.length > 2);

  if (words1.length > 0 && words2.length > 0) {
    let matchedWords = 0;

    for (const w1 of words1) {
      for (const w2 of words2) {
        if (w1 === w2) {
          matchedWords += 1.0;
          break;
        }
        const wordSim = similarityScore(w1, w2);
        if (wordSim >= 0.85) {
          matchedWords += wordSim;
          break;
        }
      }
    }

    const wordScore = matchedWords / Math.max(words1.length, words2.length);
    if (wordScore >= 0.6) {
      return 0.70 + (wordScore * 0.15);
    }
  }

  // 5. مقارنة التشابه العام
  const overallSim1 = similarityScore(norm1, norm2);
  const overallSim2 = similarityScore(stripped1, stripped2);
  const maxSim = Math.max(overallSim1, overallSim2);

  if (maxSim >= 0.65) {
    return maxSim * 0.85;
  }

  return 0;
}

/**
 * استخراج جميع المعرفات الممكنة من البيانات
 */
function extractCompanyIdentifiers(data, isFile = false) {
  const identifiers = [];

  if (isFile && data.fileName) {
    const fromFileName = extractCompanyNameFromFileName(data.fileName);
    if (fromFileName) {
      identifiers.push(fromFileName);

      const cleaned = cleanSpecialPrefixes(fromFileName);
      if (cleaned && cleaned !== fromFileName) {
        identifiers.push(cleaned);
      }

      const stripped = stripCompanySuffixes(fromFileName);
      if (stripped && stripped !== cleaned) {
        identifiers.push(stripped);
      }
    }
  }

  const possibleFields = [
    'companyName', 'Company Name', 'company_name',
    'taxFolderName', 'Tax Folder Name', 
    'name', 'Name', 'title', 'Title'
  ];

  for (const field of possibleFields) {
    if (data[field]) {
      const value = String(data[field]).trim();
      if (value) {
        const cleaned = cleanSpecialPrefixes(value);
        identifiers.push(cleaned);

        const stripped = stripCompanySuffixes(cleaned);
        if (stripped && stripped !== cleaned) {
          identifiers.push(stripped);
        }

        const normalized = normalizeText(cleaned);
        if (normalized && normalized !== cleaned) {
          identifiers.push(normalized);
        }
      }
    }
  }

  return [...new Set(identifiers)].filter(Boolean);
}

