// ===== Helpers =====
function normalizeText(text) {
  if (!text) return "";
  return String(text)
    // remove zero-width & RTL marks
    .replace(/[\u200B-\u200F\u061C]/g, "")
    // NFKD + strip diacritics
    .normalize("NFKD").replace(/[\u0300-\u036f]/g, "")
    // Turkish casing quirks
    .replace(/İ/g, "i").replace(/ı/g, "i")
    // unify spaces & lowercase
    .toLowerCase().replace(/\s+/g, " ").trim();
}

function stripTaxPrefix(name) {
  const n = normalizeText(name);
  return n.replace(/^tax\s+/, "").trim();
}

function companyKey(obj) {
  // جرّب companyName/ company_name
  const byCompany = normalizeText(obj.company_name || obj.companyName || "");
  if (byCompany) return byCompany;
  // وإلا استخرج من اسم الفولدر بدون TAX
  return stripTaxPrefix(obj.folder_name || obj.folderName || "");
}

