/**
 * Extract & Normalize Kommo Contacts (post-search)
 * - يُرجع عنصرًا لكل phone_query (وأيضًا لكل عنصر مجهول بمفتاح فريد).
 * - يعمل حتى لو استجابة HTTP كانت فارغة.
 * - يضيف عدادات/رايات للتكرار + route_hint للتوجيه.
 */

// ============ Helpers ============
const toStr = v => (v == null ? "" : String(v).trim());

function getFieldValues(cfv, code) {
  const out = [];
  if (!Array.isArray(cfv)) return out;
  const target = String(code || "").toUpperCase();
  for (const f of cfv) {
    if (String(f.field_code || "").toUpperCase() !== target) continue;
    const vals = f.values || [];
    for (const v of vals) out.push(toStr(v.value));
  }
  return out;
}

function decodeFromHref(href, key = "query") {
  const m = toStr(href).match(new RegExp(`[?&]${key}=([^&]+)`));
  if (!m) return "";
  try { return decodeURIComponent(m[1]); } catch { return m[1]; }
}

function pickPhoneQuery(j, parsed) {
  if (j.phone_query) return j.phone_query;
  if (j.phone_query_encoded) {
    try { return decodeURIComponent(j.phone_query_encoded); } catch { return j.phone_query_encoded; }
  }
  const href = parsed?._links?.self?.href || j.url || "";
  const fromHref = decodeFromHref(href, "query");
  if (fromHref) return fromHref;

  if (j.primary_query_value && /^\+?\d/.test(j.primary_query_value)) return String(j.primary_query_value);
  if (j.phone_1 && /^\+?\d/.test(j.phone_1)) return String(j.phone_1);

  return "(unknown)";
}

// ============ Main ============
const grouped = new Map(); // key = phone_query (or unique unknown#idx)

for (let idx = 0; idx < items.length; idx++) {
  const it = items[idx];
  const j = it.json || {};

  // parse response body (supports json.data as string/object, or json directly)
  let parsed = {};
  if (typeof j.data === "string") {
    try { parsed = JSON.parse(j.data); } catch { parsed = {}; }
  } else if (j.data && typeof j.data === "object") {
    parsed = j.data;
  } else if (typeof j === "object") {
    parsed = j;
  }

  // phone key (unique for unknowns)
  let phoneQuery = pickPhoneQuery(j, parsed);
  if (!phoneQuery || phoneQuery === "(unknown)") phoneQuery = `(unknown#${idx + 1})`;

  // ensure bucket
  if (!grouped.has(phoneQuery)) {
    grouped.set(phoneQuery, {
      phone_query: phoneQuery,
      contact_ids_set: new Set(),
      lead_ids_set: new Set(),
      company_ids_set: new Set(),
      contacts: []
    });
  }
  const acc = grouped.get(phoneQuery);

  // contacts array (may be empty)
  const contactsArr = Array.isArray(parsed?._embedded?.contacts) ? parsed._embedded.contacts : [];

  for (const c of contactsArr) {
    const cid   = c?.id;
    const cname = toStr(c?.name);
    const phones = getFieldValues(c?.custom_fields_values, "PHONE");
    const emails = getFieldValues(c?.custom_fields_values, "EMAIL");
    const leadIds = (c?._embedded?.leads || []).map(l => l?.id).filter(Boolean);
    const compIds = (c?._embedded?.companies || []).map(co => co?.id).filter(Boolean);

    if (cid) acc.contact_ids_set.add(String(cid));
    leadIds.forEach(l  => acc.lead_ids_set.add(String(l)));
    compIds.forEach(co => acc.company_ids_set.add(String(co)));

    acc.contacts.push({
      contact_id: cid ?? null,
      contact_name: cname || "",
      phones, emails,
      lead_ids: leadIds,
      company_ids: compIds,
      created_at: c?.created_at ?? null,
      updated_at: c?.updated_at ?? null
    });
  }
}

// build output
const out = [];
for (const [, g] of grouped) {
  const contact_ids = Array.from(g.contact_ids_set);
  const lead_ids    = Array.from(g.lead_ids_set);
  const company_ids = Array.from(g.company_ids_set);

  const contact_count = contact_ids.length;
  const lead_count    = lead_ids.length;
  const company_count = company_ids.length;

  const has_duplicates_contacts  = contact_count > 1;
  const has_duplicates_leads     = lead_count > 1;
  const has_duplicates_companies = company_count > 1;

  let found_state = "NOT_FOUND";
  const total = contact_count + lead_count + company_count;
  if (total === 1) found_state = "SINGLE";
  else if (total > 1) found_state = "DUPLICATES";

  const route_hint =
    found_state === "NOT_FOUND"  ? "NOT_FOUND" :
    found_state === "SINGLE"     ? "PASS_EXISTING" :
                                    "BLOCKED";

  const warnings = [];
  if (has_duplicates_contacts)  warnings.push(`Duplicate contacts: ${contact_ids.join(", ")}`);
  if (has_duplicates_leads)     warnings.push(`Duplicate leads: ${lead_ids.join(", ")}`);
  if (has_duplicates_companies) warnings.push(`Duplicate companies: ${company_ids.join(", ")}`);

  out.push({
    json: {
      phone_query: g.phone_query,

      contact_ids, lead_ids, company_ids,
      contact_count, lead_count, company_count,

      has_duplicates_contacts,
      has_duplicates_leads,
      has_duplicates_companies,

      found_state,      // NOT_FOUND | SINGLE | DUPLICATES
      route_hint,       // NOT_FOUND | PASS_EXISTING | BLOCKED

      contacts: g.contacts,
      warnings_text: warnings.join(" | ")
    }
  });
}

// absolute fallback (shouldn't happen with the unique unknown keys)
if (out.length === 0) {
  out.push({ json: {
    phone_query: "(unknown)",
    contact_ids: [], lead_ids: [], company_ids: [],
    contact_count: 0, lead_count: 0, company_count: 0,
    has_duplicates_contacts: false,
    has_duplicates_leads: false,
    has_duplicates_companies: false,
    found_state: "NOT_FOUND",
    route_hint: "NOT_FOUND",
    contacts: [],
    warnings_text: "No HTTP response data found"
  }});
}

return out;

