  });

  ['last_name', 'lastName'].forEach(key => {
    if (item[key]) info.names.last = item[key];
  });

  ['full_name', 'fullName', 'contact_name', 'lead_name'].forEach(key => {
    if (item[key] && item[key] !== "No data") {
      info.names.full = item[key];
    }
  });

  // استخراج الهواتف
  ['phone_1', 'phone_2', 'phone_3', 'phone_query', 'primary_query_value'].forEach(key => {
    if (item[key] && item[key].includes('+')) {
      info.phones.push(item[key]);
    }
  });

  if (item.phone_values && Array.isArray(item.phone_values)) {
    info.phones.push(...item.phone_values);
  }

  // استخراج الإيميلات
  ['email_1', 'email_2', 'email_3', 'contact_email'].forEach(key => {
    if (item[key] && item[key].includes('@')) {
      info.emails.push(item[key]);
    }
  });

  if (item.email_values && Array.isArray(item.email_values)) {
    info.emails.push(...item.email_values);
  }

  // من all_records إن وجد
  if (item.all_records) {
    item.all_records.forEach(r => {
      // أسماء
      if (r.first_name) info.names.first = r.first_name;
      if (r.last_name) info.names.last = r.last_name;
      if (r.full_name) info.names.full = r.full_name;

      // هواتف
      ['phone_1', 'phone_2', 'phone_query'].forEach(key => {
        if (r[key] && r[key].includes('+')) info.phones.push(r[key]);
      });

      // إيميلات
      ['email_1', 'email_2', 'contact_email'].forEach(key => {
        if (r[key] && r[key].includes('@')) info.emails.push(r[key]);
      });
    });
  }

  // إزالة المكررات
  info.phones = [...new Set(info.phones)];
  info.emails = [...new Set(info.emails)];

  return info;
};

// دالة لاستخراج Tags
const extractTags = (item) => {
  const tags = {
    names: [],
    ids: [],
    objects: []
  };

  // من الحقل المباشر
  if (item.tags && Array.isArray(item.tags)) {
    tags.names.push(...item.tags);
  }

  if (item.tag_ids && Array.isArray(item.tag_ids)) {
    tags.ids.push(...item.tag_ids);
  }

  if (item.tag_objects && Array.isArray(item.tag_objects)) {
    tags.objects.push(...item.tag_objects);
  }

  // من all_records
  if (item.all_records) {
    item.all_records.forEach(r => {
      if (r.tags) tags.names.push(...r.tags);
      if (r.tag_ids) tags.ids.push(...r.tag_ids);
      if (r.tag_objects) tags.objects.push(...r.tag_objects);
    });
  }

  // إزالة المكررات
  tags.names = [...new Set(tags.names)];
  tags.ids = [...new Set(tags.ids)];

  // إزالة tag_objects المكررة بناءً على ID
  const seenTagIds = new Set();
  tags.objects = tags.objects.filter(obj => {
    if (!seenTagIds.has(obj.id)) {
      seenTagIds.add(obj.id);
      return true;
    }
    return false;
  });

  return tags;
};

