function calculateCompleteness(data, contactInfo, allIds, companyId) {
  let score = 0;
  let total = 7;

  if (data.lead_id) score++;
  if (data.contact_id) score++;
  if (companyId) score++;
  if (contactInfo.names.full) score++;
  if (contactInfo.phones.length > 0) score++;
  if (contactInfo.emails.length > 0) score++;
  if (data.folder_name) score++;

  return {
    score: score,
    total: total,
    percentage: Math.round((score / total) * 100),
    status: score >= 5 ? "Good" : score >= 3 ? "Fair" : "Poor"
  };
}

