// n8n Function — Normalize + Merge + Route (with phone/email fallback)

// Helpers
const splitInline = (arr) => arr.flatMap(x =>
  String(x ?? '')
    .split(/[;,]/)
    .map(s => s.trim())
    .filter(Boolean)
);
const toArr = (v) => Array.isArray(v) ? v : (v == null || v === '' ? [] : [v]);
const uniq = (arr) => [...new Set(arr.filter(v => v !== '' && v != null))];
const normPhone = (s) => String(s || '')
  .replace(/[^\d+]/g, '')
  .replace(/^0+/, '')
  .replace(/^\+?(\d+)$/, '+$1');
const first = (...vals) => vals.find(v => v != null && v !== '') || null;
const parseJsonSafe = (s) => { try { return JSON.parse(s); } catch { return String(s||'').match(/\d+/g)?.map(Number) || []; } };

// Normalize one item
function normalize(j) {
  const lead_id    = j.lead_id    ?? j.leadId    ?? null;
  const contact_id = j.contact_id ?? j.contactId ?? null;
  const company_id = j.company_id ?? j.companyId ?? null;

  const folder_id   = first(j.folder_id, j.folderId, j.original_data?.folder_Id);
  const folder_name = first(j.folder_name, j.folderName, j.original_data?.folder_name);
  const document_id   = first(j.document_id, j.documentId, j.original_data?.document_id, j.documentID);
  const document_name = first(j.document_name, j.documentName, j.original_data?.document_name);

  // Phones
  const phonesRaw = [
    ...toArr(j.all_phones),
    ...toArr(j.phone_values),
    j.primary_phone,
    j.phone_1,
    j.phone_query,
    j.contact_phone
  ];
  const phones = uniq(phonesRaw.map(normPhone).filter(Boolean));

  // Emails (split even if array elements contain ';' or ',')
  const emailsRaw = [
    ...toArr(j.all_emails),
    ...toArr(j.email_values),
    j.primary_email,
    j.email_1, j.email_2, j.email_3,
    j.contact_email
  ].filter(Boolean);
  const emails = uniq(splitInline(emailsRaw));

  const tag_names = uniq(splitInline([
    ...toArr(j.tag_names),
    ...toArr(j.tags),
    j.tags_string
  ].filter(Boolean)));

  const tag_ids = uniq([
    ...toArr(j.tag_ids),
    ...parseJsonSafe(j.tagıd),
    ...parseJsonSafe(j.tagId),
  ].map(n => Number(n)).filter(n => !Number.isNaN(n)));

  const company_name = first(j.company_name, j.companyName, j.original_data?.company_name);
  const full_name = first(j.full_name, j.contact_name, `${j.first_name||''} ${j.last_name||''}`.trim(), 'Unknown Contact');

  const batch_date = first(j.batch_date, j.batchDate);
  const batch_time = first(j.batch_time, j.batchtime);

  const hasLead = !!lead_id, hasContact = !!contact_id, hasCompany = !!company_id;
  const missingParts = [];
  if (!hasLead) missingParts.push('lead');
  if (!hasContact) missingParts.push('contact');
  if (!hasCompany) missingParts.push('company');

  let routing;
  if (hasLead && hasContact && hasCompany) routing = 'SKIP_COMPLETE';
  else if (hasLead && hasContact && !hasCompany) routing = 'CREATE_COMPANY_AND_LINK';
  else if (hasLead && !hasContact && hasCompany) routing = 'CREATE_CONTACT_AND_LINK';
  else if (!hasLead && hasContact && hasCompany) routing = 'CREATE_LEAD_AND_LINK';
  else routing = 'CREATE_NEW';

  return {
    lead_id, contact_id, company_id,
    company_name, full_name,
    folder_id, folder_name,
    document_id, document_name,
    all_phones: phones,
    all_emails: emails,
    primary_phone: phones[0] || null,
    primary_email: emails[0] || null,
    tag_names, tag_ids, tags_string: tag_names.join(', '),
    batch_date, batch_time,
    match_type: (hasLead && hasContact && hasCompany) ? 'all'
               : (hasLead && hasContact) ? 'both'
               : hasLead ? 'lead' : hasContact ? 'contact' : hasCompany ? 'company' : 'none',
    has_contact: hasContact,
    has_company: hasCompany,
    has_lead: hasLead,
    hasData: {
      lead: hasLead, contact: hasContact, company: hasCompany,
      phone: phones.length > 0, email: emails.length > 0,
      name: !!full_name, companyName: !!company_name
    },
    routing,
    action: routing.startsWith('SKIP') ? 'skip' : 'create',
    needsProcessing: !routing.startsWith('SKIP'),
    isComplete: routing === 'SKIP_COMPLETE',
    processed_at: new Date().toISOString(),
    original: j,
  };
}

// Pass 1: normalize all
const normalized = items.map(({json}) => normalize(json));

// Build buckets (primary by IDs), plus secondary indexes by phone/email
const buckets = new Map(); // key -> obj
const phoneIndex = new Map(); // phone -> key
const emailIndex = new Map(); // email -> key

function pickKey(n) {
  if (n.lead_id) return `L:${n.lead_id}`;
  if (n.contact_id) return `C:${n.contact_id}`;
  if (n.company_id) return `CO:${n.company_id}`;
  // try attach by phone/email to existing buckets
  for (const p of n.all_phones) if (phoneIndex.has(p)) return phoneIndex.get(p);
  for (const e of n.all_emails) if (emailIndex.has(e)) return emailIndex.get(e);
  // else fallback to folder+document (or folder+phone)
  if (n.folder_id && n.document_id) return `F:${n.folder_id}|D:${n.document_id}`;
  if (n.folder_id && n.primary_phone) return `F:${n.folder_id}|P:${n.primary_phone}`;
  if (n.primary_phone) return `P:${n.primary_phone}`;
  if (n.primary_email) return `E:${n.primary_email}`;
  return `FN:${n.folder_name}|CN:${n.company_name}`;
}

function mergeInto(ex, n) {
  const mergeArr = (a,b) => uniq([...(a||[]), ...(b||[])]);
  ex.tag_names  = mergeArr(ex.tag_names, n.tag_names);
  ex.tag_ids    = mergeArr(ex.tag_ids, n.tag_ids);
  ex.all_phones = mergeArr(ex.all_phones, n.all_phones);
  ex.all_emails = mergeArr(ex.all_emails, n.all_emails);

  ex.lead_id    = ex.lead_id    || n.lead_id;
  ex.contact_id = ex.contact_id || n.contact_id;
  ex.company_id = ex.company_id || n.company_id;

  ex.company_name = ex.company_name || n.company_name;
  ex.full_name    = ex.full_name    || n.full_name;

  ex.folder_id     = ex.folder_id     || n.folder_id;
  ex.folder_name   = ex.folder_name   || n.folder_name;
  ex.document_id   = ex.document_id   || n.document_id;
  ex.document_name = ex.document_name || n.document_name;

  ex.batch_date = ex.batch_date || n.batch_date;
  ex.batch_time = ex.batch_time || n.batch_time;

  ex.primary_phone = ex.all_phones[0] || null;
  ex.primary_email = ex.all_emails[0] || null;

  const hasLead = !!ex.lead_id, hasContact = !!ex.contact_id, hasCompany = !!ex.company_id;
  ex.missingParts = [];
  if (!hasLead) ex.missingParts.push('lead');
  if (!hasContact) ex.missingParts.push('contact');
  if (!hasCompany) ex.missingParts.push('company');

  ex.routing =
    (hasLead && hasContact && hasCompany) ? 'SKIP_COMPLETE' :
    (hasLead && hasContact && !hasCompany) ? 'CREATE_COMPANY_AND_LINK' :
    (hasLead && !hasContact && hasCompany) ? 'CREATE_CONTACT_AND_LINK' :
    (!hasLead && hasContact && hasCompany) ? 'CREATE_LEAD_AND_LINK' :
    'CREATE_NEW';

  ex.action = ex.routing.startsWith('SKIP') ? 'skip' : 'create';
  ex.needsProcessing = !ex.routing.startsWith('SKIP');
  ex.isComplete = ex.routing === 'SKIP_COMPLETE';
  ex.match_type = (hasLead && hasContact && hasCompany) ? 'all'
                : (hasLead && hasContact) ? 'both'
                : hasLead ? 'lead' : hasContact ? 'contact' : hasCompany ? 'company' : 'none';
}

// Build buckets with phone/email fallback
for (const n of normalized) {
  const key = pickKey(n);
  if (!buckets.has(key)) {
    buckets.set(key, n);
  } else {
    mergeInto(buckets.get(key), n);
  }

  // update secondary indexes
  for (const p of n.all_phones) phoneIndex.set(p, key);
  for (const e of n.all_emails) emailIndex.set(e, key);
}

return Array.from(buckets.values()).map(x => ({ json: x }));

// n8n Function: flatten Kommo+Sheet record for Google Sheets

// helpers
const first = (...vals) => vals.find(v => v !== undefined && v !== null && v !== '') ?? '';
const toArr = (v) => Array.isArray(v) ? v : (v == null || v === '' ? [] : [v]);
const joinCsv = (arr, sep=', ') => toArr(arr).filter(x => x !== null && x !== '').join(sep);

return items.map(item => {
  const d = item.json || {};
