  let tag_ids = toArr(d.tag_ids);
  // لو عندك حقل tagıd كسلسلة JSON "[1,2]"
  if (tag_ids.length === 0 && d.tagıd) {
    try { tag_ids = JSON.parse(d.tagıd); } catch { /* ignore */ }
  }

  // Batch time
  const batch_date = first(d.batch_date, d.batchDate, o.batch_date, o.batchDate);
