      // معلومات حالة (لو حابب تكتبها في أعمدة منفصلة)
      routing: d.routing || '',
      isComplete: d.isComplete ?? '',
      needsProcessing: d.needsProcessing ?? ''
    }
  };
});

// اجمع العناصر حسب leadId وامنَع التكرار في tagId
const rows = $input.all();

const byLead = new Map();

for (const { json } of rows) {
  const leadId = Number(json.leadId);
  const tagId  = Number(json.tagId);
  const tagName = json.tagName || null;

  if (!leadId || !tagId) continue;

  if (!byLead.has(leadId)) {
    byLead.set(leadId, {
      leadId,
      tagIds: new Set(),
      tagNames: new Map(), // اختياري للتوثيق
    });
  }

  const bucket = byLead.get(leadId);
  bucket.tagIds.add(tagId);
  if (tagName && !bucket.tagNames.has(tagId)) {
    bucket.tagNames.set(tagId, tagName);
  }
}

// طلّع عنصر واحد لكل lead جاهز للـ PATCH
const out = [];
for (const { leadId, tagIds, tagNames } of byLead.values()) {
  const uniqueIds = Array.from(tagIds).sort((a, b) => a - b);
  const tagsArray = uniqueIds.map(id => ({ id }));

  out.push({
    json: {
      leadId,
      // جسم الطلب الجاهز للـ PATCH
      patchBody: {
        _embedded: { tags: tagsArray }
      },
      // معلومات إضافية مفيدة (اختياري)
      tagIds: uniqueIds,
      tagNames: uniqueIds.map(id => tagNames.get(id) || null)
    }
  });
}

return out;

return items.map(item => {
