        company_id: lead._embedded?.companies?.[0]?.id || null,
        tags: tags.map(tag => tag.name),
        tag_ids: tags.map(tag => tag.id),
        tag_objects: tags
      }
    };
  } catch (e) {
    return { json: { error: e.message } };
  }
});

// n8n Code node (Normalize PDF text)
return $input.all().map(item => {
  const text = item.json.text || "";
  return { json: { ...item.json, text } };
});

// n8n Code node — Extract company + tax meta from Turkish tax PDFs (enhanced version)

const items = $input.all();

/* ======================= Helpers ======================= */

const normalize = (str = "") =>
  str.toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/ı/g, "i")
    .replace(/ş/g, "s")
    .replace(/ğ/g, "g")
    .replace(/ç/g, "c")
    .replace(/ö/g, "o")
    .replace(/ü/g, "u")
    .replace(/\s+/g, " ")
    .trim();

const monthNameTR = (mm) => ({
  "01":"Ocak","02":"Şubat","03":"Mart","04":"Nisan","05":"Mayıs","06":"Haziran",
  "07":"Temmuz","08":"Ağustos","09":"Eylül","10":"Ekim","11":"Kasım","12":"Aralık"
}[mm] || null);

/**
 * إزالة حالات التصفية والبادئات الخاصة
 */
const removeLiquidationStatus = (name = "") => {
  if (!name) return name;

  let cleaned = name.trim();

  // أنماط حالات التصفية المختلفة
  const liquidationPatterns = [
    /^TASF\.?\s*HAL\.?\s*/i,           // TASF.HAL. أو TASF HAL
    /^TASFİYE\s+HALİNDE\s*/i,          // TASFİYE HALİNDE
    /^TASFİYEDE\s*/i,                  // TASFİYEDE
    /^TAS\.?\s*HAL\.?\s*/i,            // TAS.HAL
    /^T\.H\.\s*/i,                     // T.H.
    /^LIQUIDATION\s*/i,                // LIQUIDATION
    /^IN\s+LIQUIDATION\s*/i,           // IN LIQUIDATION
    /^LİKİDASYON\s*/i,                 // LİKİDASYON
    /^FESİH\s+HALİNDE\s*/i,            // FESİH HALİNDE (في حالة الإلغاء)
  ];

  // إزالة حالات التصفية
  for (const pattern of liquidationPatterns) {
    cleaned = cleaned.replace(pattern, "").trim();
  }

  // إزالة النقاط المتبقية من البداية
  cleaned = cleaned.replace(/^\.+/, "").trim();

  return cleaned;
};

/**
 * تنظيف الاسم من الكلمات الزائدة والعناوين مع الحفاظ على حالات التصفية
 */
const cleanCompanyName = (raw = "") => {
  if (!raw) return null;

  let cleaned = raw.trim();

  // إزالة حالات التصفية أولاً
  cleaned = removeLiquidationStatus(cleaned);

  // إزالة العناوين والأرقام الطويلة
  cleaned = cleaned.replace(/\b\d{10,}\b/g, ""); // إزالة الأرقام الطويلة جداً
  cleaned = cleaned.replace(/\d{6,}-\d+\/\d+/g, ""); // إزالة أرقام السجل
  cleaned = cleaned.replace(/\b\d{4}\/\d{2}\/\d{4}\b/g, ""); // إزالة التواريخ

  // إزالة المسارات والعناوين
  const addressPatterns = [
    /BEŞYOL\s+MAH[\s\S]*?KÜÇÜKÇEKMECE/gi,
    /\bMAH\.?\s+[^,\n]*/gi,
    /\bSK\.?\s+[^,\n]*/gi,
    /\bCAD\.?\s+[^,\n]*/gi,
    /\bBLV\.?\s+[^,\n]*/gi,
    /Dış\s+kapı\s+no:\d+/gi,
    /İç\s+kapı\s+no:\d+/gi,
    /Kapı\s+No:\d+/gi,
    /Daire\s+No:\d+/gi
  ];

  for (const pattern of addressPatterns) {
    cleaned = cleaned.replace(pattern, " ");
  }

  // إزالة أسماء المدن
  const cities = [
    "İSTANBUL", "KÜÇÜKÇEKMECE", "BEYLİKDÜZÜ", "BAŞAKŞEHİR",
    "BAHÇELİEVLER", "ESENYURT", "ÜMRANİYE", "AVCILAR"
  ];

  for (const city of cities) {
    cleaned = cleaned.replace(new RegExp(`\\b${city}\\b`, 'gi'), "");
  }

  // تنظيف نهائي
  cleaned = cleaned
    .replace(/[\/\-–—,;:|()]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  return cleaned.length > 2 ? cleaned : null;
};

/* ========== Extract Company Name (enhanced for liquidation cases) ========== */

const extractCompanyFromText = (text = "", fileName = "") => {
  if (!text) return null;

  const lines = text.split(/\r?\n/).map(l => l.trim()).filter(Boolean);

  // === حالة 1: وثائق SGK - البحث عن Unvanı متبوعاً باسم الشركة ===
  for (let i = 0; i < lines.length - 5; i++) {
    const line = lines[i];

    // البحث عن سطر يحتوي على كلمة Unvanı فقط أو مع نقطتين
    if (line.match(/^Unvanı\s*:?\s*$/i)) {
      // البحث في الأسطر التالية عن اسم الشركة
      for (let j = 1; j <= 5; j++) {
        const nextLine = lines[i + j];
        if (!nextLine) continue;

        // تجنب الأسطر التي تحتوي على معلومات أخرى
        if (nextLine.match(/^(ADRES|BEŞ|YAK|GÜL|MEH|NAM|CUM|İKİ|HÜR|PİR)/i)) continue;
        if (nextLine.match(/^\d{6,}/)) continue; // أرقام طويلة
        if (nextLine.match(/^\d+\s*\/\s*/)) continue; // تواريخ أو أرقام

        // البحث عن أسماء الشركات بالكلمات المفتاحية
        if (nextLine.match(/(ŞİRKET|TİCARET|SANAYİ|LOJİSTİK|PERAKENDE|İTHALAT|İHRACAT|LİMİTED|LTD|GROUP|PLATFORM|MEDİKAL|DANIŞMANLIK|OTOMOTİV|GAYRİMENKUL|ARAÇ|MEDYA|BUSINESS|EXPERTS)/i)) {
          const cleaned = cleanCompanyName(nextLine);
          if (cleaned && cleaned.length > 5) {
            return cleaned;
          }
        }

        // إذا كان السطر يبدأ بحالة تصفية، نعالجه أيضاً
        if (nextLine.match(/^(TASF|TASFİYE|LİKİDASYON)/i)) {
          const cleaned = cleanCompanyName(nextLine);
          if (cleaned && cleaned.length > 5) {
            return cleaned;
          }
        }
      }
    }
  }

  // === حالة 2: وثائق الضرائب - SOYADI (UNVANI) NAME ===
  for (let i = 0; i < lines.length - 1; i++) {
    const line = lines[i];

    // Pattern: SOYADI (UNVANI) COMPANY_NAME
    const pattern1 = /^SOYADI\s*\(\s*UNVANI\s*\)\s+(.+)$/i;
    const match1 = line.match(pattern1);
    if (match1 && match1[1]) {
      let companyName = match1[1].trim();

      // إزالة حالة التصفية إن وجدت
      companyName = removeLiquidationStatus(companyName);

      // إذا كان اسم شخص (كلمة واحدة)، ابحث عن الاسم الأول
      if (!companyName.includes(" ") && i + 1 < lines.length) {
        const nextLine = lines[i + 1];
        if (nextLine.match(/^ADI\s+(.+)$/i)) {
          const firstName = nextLine.replace(/^ADI\s+/i, "").trim();
          return `${firstName} ${companyName}`.trim();
        }
      }

      // إذا كان اسم شركة
      if (companyName.match(/(TİCARET|ŞİRKET|LİMİTED|İTHALAT|İHRACAT|LOJİSTİK|PLATFORM|GROUP)/i) || 
          companyName.length > 5) {
        return companyName;
      }

      // إرجاع الاسم كما هو
      return companyName;
    }

    // Pattern: SOYADI (UNVANI) متبوع بالاسم في السطر التالي
    if (line.match(/^SOYADI\s*\(\s*UNVANI\s*\)\s*$/i) && i + 1 < lines.length) {
      let nextLine = lines[i + 1];

      // إزالة حالة التصفية إن وجدت
      nextLine = removeLiquidationStatus(nextLine);

      if (!nextLine.match(/^(ADI|KABUL|VERGİ|ADRES)/i) && nextLine.length > 2) {
        return nextLine.trim();
      }
    }
  }

  // === حالة 3: İşyeri Ünvanı ===
  for (let i = 0; i < lines.length - 1; i++) {
    const line = lines[i];

    if (line.match(/^İşyeri\s+Ünvanı\s*:?\s*$/i)) {
      // الاسم في السطر التالي
      for (let j = 1; j <= 3; j++) {
        let nextLine = lines[i + j];
        if (!nextLine) continue;

        // إزالة حالة التصفية أولاً
        const cleanedLine = removeLiquidationStatus(nextLine);

        // تجنب العناوين
        if (cleanedLine.match(/^(BEŞYOL|YAKUPLU|GÜLTEPE|MEHMET|NAMIK|CUMHURİYET|İKİTELLİ|HÜRRİYET|PİRİ)/i)) continue;

        // إذا وجدنا اسم شركة
        if (cleanedLine.length > 5 && !cleanedLine.match(/^\d/)) {
          const finalCleaned = cleanCompanyName(nextLine); // نمرر النص الأصلي للتنظيف الكامل
          if (finalCleaned && finalCleaned.length > 5) {
            return finalCleaned;
          }
        }
      }
    }
  }

  // === حالة 4: البحث العام عن أسماء الشركات ===
  const companyKeywords = [
    "ŞİRKETİ", "ŞİRKET", "TİCARET", "SANAYİ", "LOJİSTİK",
    "İTHALAT", "İHRACAT", "LİMİTED", "LTD", "ANONİM",
    "DANIŞMANLIK", "MEDİKAL", "MEDYA", "GROUP", "BUSINESS",
    "PLATFORM", "OTOMOTİV", "GAYRİMENKUL", "PERAKENDE", "ARAÇ",
    "CURE", "ALOSS", "EXPERTS", "OVERSEAS"
  ];

  for (const line of lines) {
    // تجنب أسطر العناوين
    if (line.match(/^(T\.C\.|VERGİ|TAHAKKUK|ADRES|MAKİNA|KABUL|SOYADI|ADI\s|Unvanı)/i)) continue;

    // تنظيف السطر من حالات التصفية
    const cleanedLine = removeLiquidationStatus(line);

    for (const keyword of companyKeywords) {
      if (cleanedLine.toUpperCase().includes(keyword)) {
        const finalCleaned = cleanCompanyName(line);
        if (finalCleaned && finalCleaned.length > 10 && !finalCleaned.match(/^(UNVANI|ADI|SOYADI)/i)) {
          return finalCleaned;
        }
      }
    }
  }

  return null;
};

/* ========== Extract Document Type ========== */

const extractDocumentType = (text = "", fileName = "") => {
  const nText = normalize(text);
  const nName = normalize(fileName);

  // SGK وثائق - نوع واحد فقط
  if (nText.includes("sosyal guvenlik kurumu") || 
      nText.includes("sigorta primleri genel") ||
      nText.includes("sigortali hizmet listesi")) {
    return "SGK";
  }

  // KDV وثائق
  if (nText.includes("katma deger vergisi tevkifati")) {
    return "KDV Tevkifat";
  }
  if (nText.includes("katma deger vergisi") || nText.includes("kdv")) {
    return "KDV";
  }

  // ضريبة الدخل والاستقطاع - فقط Muhtasar
  if (nText.includes("gelir vergisi") && nText.includes("muhtasar")) {
    return "Muhtasar";
  }
  if (nText.includes("muhtasar")) {
    return "Muhtasar";
  }

  // ضريبة الشركات
  if (nText.includes("kurum gecici vergi")) {
    return "Kurumlar Geçici";
  }
  if (nText.includes("kurumlar vergisi") || nText.includes("kurum vergisi")) {
    return "Kurumlar";
  }

  // التحقق من رمز الضريبة
  const taxCodeMatch = text.match(/Ana\s+Vergi\s+Kodu\s+0*([0-9]+)/i);
  if (taxCodeMatch) {
    const code = taxCodeMatch[1];
    switch(code) {
      case "3": return "Muhtasar";
      case "10": return "Kurumlar";
      case "15": return "KDV";
      case "33": return "Kurumlar Geçici";
      case "4017": return "KDV Tevkifat";
      default: return `Vergi Kodu ${code}`;
    }
  }

  return "Bilinmeyen";
};

/* ========== Extract Period ========== */

const extractPeriod = (text = "", fileName = "") => {
  const all = `${text}\n${fileName}`;

  // Pattern 1: AİT OLDUĞU YIL / AY (SGK format)
  let match = all.match(/AİT\s+OLDUĞU\s+YIL\s*\/\s*AY[^0-9]*(\d{4})\/(\d{2})/i);
  if (match) {
    return { 
      monthNumber: match[2], 
      monthName: monthNameTR(match[2]), 
      year: match[1] 
    };
  }

  // Pattern 2: Direct year/month pattern in SGK documents
  match = all.match(/(\d{4})\/(\d{2})\s*$/m);
  if (match) {
    return { 
      monthNumber: match[2], 
      monthName: monthNameTR(match[2]), 
      year: match[1] 
    };
  }

  // Pattern 3: Vergilendirme Dönemi
  match = all.match(/Vergilendirme\s+Dönemi[^0-9]*(\d{2})\/(\d{4})/i);
  if (match) {
    return { 
      monthNumber: match[1], 
      monthName: monthNameTR(match[1]), 
      year: match[2] 
    };
  }

  // Pattern 4: Yıl - Ay (alternative SGK format)
  match = all.match(/Yıl\s*-\s*Ay[^0-9]*(\d{4})\/(\d{2})/i);
  if (match) {
    return { 
      monthNumber: match[2], 
      monthName: monthNameTR(match[2]), 
      year: match[1] 
    };
  }

  // Pattern 5: Date range (04/2025-06/2025)
  match = all.match(/(\d{2})\/(\d{4})\s*-\s*(\d{2})\/(\d{4})/);
  if (match) {
    // نأخذ التاريخ النهائي
    return { 
      monthNumber: match[3], 
      monthName: monthNameTR(match[3]), 
      year: match[4] 
    };
  }

  // Pattern 6: Simple date MM/YYYY
  match = all.match(/(\d{2})\/(\d{4})/);
  if (match && parseInt(match[1]) <= 12) {
    return { 
      monthNumber: match[1], 
      monthName: monthNameTR(match[1]), 
      year: match[2] 
    };
  }

  return { 
    monthNumber: null, 
    monthName: null, 
    year: null 
  };
};

/* ========== Extract Total Amount ========== */

const parseTurkishAmount = (s) => {
  if (!s) return null;
  let cleaned = s.replace(/\s/g, "");
  cleaned = cleaned.replace(/\./g, "").replace(/,/, ".");
  const value = parseFloat(cleaned);
  return isNaN(value) ? null : value;
};

const extractTotalAmount = (text = "") => {
  if (!text) return null;

  // أنماط خاصة بـ SGK
  const sgkPatterns = [
    { regex: /ÖDENECEK\s+NET\s+TUTAR\s+([0-9.,\s]+)/gi, priority: 1 },
    { regex: /NET\s+PRİM\s+TUTARI\s+([0-9.,\s]+)/gi, priority: 2 },
    { regex: /TOPLAM\s+PRİM\s+([0-9.,\s]+)/gi, priority: 2 },
    { regex: /İŞSİZLİK\s+TUTARI[^0-9]*([0-9.,\s]+)/gi, priority: 3 },
  ];

  // أنماط عامة للضرائب الأخرى
  const generalPatterns = [
    { regex: /TOPLAM\s+([0-9.,\s]+)/gi, priority: 1 },
    { regex: /ÖDENECEK\s+OLAN[^0-9]*([0-9.,\s]+)/gi, priority: 2 },
  ];

  // تحديد نوع الوثيقة
  const isSGK = text.includes("SOSYAL GÜVENLİK KURUMU");
  const patterns = isSGK ? [...sgkPatterns, ...generalPatterns] : [...generalPatterns, ...sgkPatterns];

  const amounts = [];

  for (const { regex, priority } of patterns) {
    let match;
    regex.lastIndex = 0;
    while ((match = regex.exec(text)) !== null) {
      if (match[1]) {
        const amount = parseTurkishAmount(match[1]);
        if (amount !== null && amount > 0) {
          amounts.push({ value: amount, priority });
        }
      }
    }
  }

  // في وثائق SGK، ابحث عن السطر الأخير الذي يحتوي على رقم
  if (isSGK && amounts.length > 0) {
    // البحث عن آخر قيمة رقمية كبيرة في النص
    const lastNumberPattern = /([0-9]+\.?[0-9]*,\d{2})\s*$/gm;
    let lastMatch;
    let match;
    while ((match = lastNumberPattern.exec(text)) !== null) {
      lastMatch = match;
    }
    if (lastMatch && lastMatch[1]) {
      const lastAmount = parseTurkishAmount(lastMatch[1]);
      if (lastAmount && lastAmount > 100) { // فقط المبالغ الكبيرة
        amounts.push({ value: lastAmount, priority: 0 }); // أعلى أولوية
      }
    }
  }

  if (amounts.length > 0) {
    amounts.sort((a, b) => {
      if (a.priority !== b.priority) return a.priority - b.priority;
      return b.value - a.value;
    });
    return amounts[0].value;
  }

  return null;
};

/* ======================= MAIN ======================= */

return items.map((item, index) => {
  const text = item.json?.text || "";
  const fileName = item.json?.name || item.json?.fileName || "";
  const id = item.json?.id ?? item.json?.fileId ?? index;

  const companyName = extractCompanyFromText(text, fileName);
  const documentType = extractDocumentType(text, fileName);
  const period = extractPeriod(text, fileName);
  const totalAmount = extractTotalAmount(text);

  // التحقق من صحة اسم الشركة
  const validCompanyName = companyName && 
    !companyName.match(/^(unvani|ünvani|işyeri|adi|soyadi)$/i) ? 
    companyName : "غير محدد";

  // إضافة معلومة إذا كانت الشركة في حالة التصفية
  const originalText = text || "";
  const isInLiquidation = originalText.match(/(TASF\.?\s*HAL\.?|TASFİYE\s+HALİNDE|TASFİYEDE|LİKİDASYON)/i);

  return {
    json: {
      id: id,
      fileName: fileName || "غير محدد",
      companyName: validCompanyName,
      normalizedName: validCompanyName !== "غير محدد" ? normalize(validCompanyName) : null,
      companyStatus: isInLiquidation ? "في حالة التصفية" : "نشط",
      documentType: documentType,
      monthNumber: period.monthNumber || "غير محدد",
      monthName: period.monthName || "غير محدد",
      year: period.year || "غير محدد",
      totalAmount: totalAmount || 0,
      formattedAmount: totalAmount ? 
        new Intl.NumberFormat('tr-TR', { 
          style: 'currency', 
          currency: 'TRY' 
        }).format(totalAmount) : "0,00 ₺",
      extractionStatus: {
        hasCompanyName: validCompanyName !== "غير محدد",
        hasDocumentType: documentType !== "Bilinmeyen",
        hasPeriod: !!period.monthNumber,
        hasAmount: !!totalAmount
      }
    }
  };
});

// ===== Helpers =====
const splitMultiPhones = (value) =>
  String(value || '')
    .split(/[,،;\/]+/g)              // نفصل لو في أكتر من رقم
    .map(s => s.trim())
    .filter(Boolean);

const extractEmails = (value) =>
  String(value || '')
    .split(/[,،;\/\s]+/g)            // الإيميلات ممكن تتفصل بمسافات
    .map(s => s.trim())
    .filter(Boolean);

const normalizePhone = (raw) => {
  if (!raw) return '';
  let p = String(raw).trim();
  p = p.replace(/^00/, '+');         // 00.. -> +
  p = p.replace(/[^\d+]/g, '');      // اسمح بالأرقام و + فقط
  const plusCount = (p.match(/\+/g) || []).length;
  if (plusCount > 1) {
    let seen = false;
    p = p.split('').filter(ch => {
      if (ch === '+') { if (seen) return false; seen = true; }
      return true;
    }).join('');
  }
  return p;
};

const normalizeEmail = (e) => String(e || '').toLowerCase().trim();
const normText = (t) => String(t || '').toLowerCase().replace(/\s+/g, ' ').trim();

// ===== استبعاد الشركات غير المطابقة =====
const filteredItems = items.filter(item => item.json?.status === true);

// ===== Build map per contact inside same folder/company =====
const map = new Map();

for (const item of filteredItems) {
  const row = item.json;

  const folderName = row.folderName || row.folder_name || '';
  const folderId   = row.folderId   || row.folder_Id   || '';
  const company    = row.companyName || row.company_name || '';
  const fullName   = row.full_name || row.contact_name || '';

  const key = `${normText(fullName)}|${normText(folderName || company)}`;

  // تليفونات من contact_phone (قد يحتوي عدة أرقام)
  const phoneCandidates = [];
  if (row.contact_phone) phoneCandidates.push(...splitMultiPhones(row.contact_phone));

  // لو موجود phone_1..phone_5 بنجمعهم كرقم واحد
  const splitParts = [row.phone_1, row.phone_2, row.phone_3, row.phone_4, row.phone_5]
    .map(x => (x == null ? '' : String(x).trim()))
    .filter(Boolean);
  if (splitParts.length) phoneCandidates.push(splitParts.join(' '));

  const normPhones = phoneCandidates.map(normalizePhone).filter(Boolean);

  // الإيميلات من contact_email + email_1..email_5
  const emailCandidates = [];
  if (row.contact_email) emailCandidates.push(...extractEmails(row.contact_email));
  for (let i = 1; i <= 5; i++) {
    if (row[`email_${i}`]) emailCandidates.push(row[`email_${i}`]);
  }
  const normEmails = emailCandidates.map(normalizeEmail).filter(Boolean);

  if (!map.has(key)) {
    map.set(key, {
      contact_name: fullName || '',
      company_name: company || '',
      folder_name: folderName || '',
      folder_Id: folderId || '',
      phones: new Set(normPhones),
      emails: new Set(normEmails),
      batch_date: row.batchDate || row.batch_date || '',
      batch_time: row.batchtime || row.batch_time || ''
    });
  } else {
    const ex = map.get(key);
    normPhones.forEach(p => ex.phones.add(p));
    normEmails.forEach(e => ex.emails.add(e));
  }
}

// ===== Flatten to output: keep ONLY first phone, emails up to 5 =====
const out = [];
for (const entry of map.values()) {
  // رتّب الأرقام وخد الأول فقط
  const phones = Array.from(entry.phones).sort((a, b) => b.length - a.length);
  const firstPhone = phones[0] || '';

  // الإيميلات (حتى 5 كما هي)
  const emails = Array.from(entry.emails).slice(0, 5);

  // الاستعلام الأساسي يفضّل الهاتف الأول
  let primary_query_type = '';
  let primary_query_value = '';
  if (firstPhone) {
    primary_query_type = 'phone';
    primary_query_value = firstPhone;
  } else if (emails[0]) {
    primary_query_type = 'email';
    primary_query_value = emails[0];
  }

  // حقول الهاتف: فقط phone_1 إن وجد
  const phoneFields = {};
  if (firstPhone) phoneFields.phone_1 = firstPhone;

  // حقول الإيميل: ديناميكيًا بدون فراغات
  const emailFields = {};
  emails.forEach((e, idx) => { emailFields[`email_${idx+1}`] = e; });

  out.push({
    json: {
      contact_name: entry.contact_name,
      company_name: entry.company_name,
      folder_name: entry.folder_name,
      folder_Id: entry.folder_Id,
      ...phoneFields,                // فقط phone_1 لو موجود
      ...emailFields,                // email_1..email_n الموجودين فقط
      primary_query_type,
      primary_query_value,
      batch_date: entry.batch_date,
      batch_time: entry.batch_time
    }
  });
}

return out;

// ========================================
// الكود النهائي - بدون UNIQUE_ID
// يمنع التكرار محلياً باستخدام رقم الهاتف
// ========================================

const SUBDOMAIN = "infodvnlogcom";
const PIPELINE_ID = 11613083;
const STATUS_ID = 89191851;
const RESPONSIBLE_USER_ID = 12924735;
const FIXED_TAGS = [{ name: "MonthlyTax" }];

// Helper functions
const isNonEmpty = v => v != null && String(v).trim() !== "";
const toStr = v => (v == null ? "" : String(v)).trim();
const uniq = arr => [...new Set(arr.filter(isNonEmpty))];
const normalizePhone = p => toStr(p).replace(/[^\d+]+/g, "");

// Process all items
const allItems = $input.all();
const processedPhones = new Set(); // لتتبع الأرقام المعالجة
const leadsToCreate = [];
const skippedDuplicates = [];

for (const item of allItems) {
  const d = item.json || {};
  const records = Array.isArray(d.all_records) ? d.all_records : [d];
  const base = records[0] || {};

  // Extract primary phone for duplicate checking
  const phones = [
    base.phone_1,
    base.phone_2,
    base.phone_values?.[0],
    base.contact_phone
  ].filter(p => p && p.toString().trim());

  if (phones.length === 0) {
    console.log("Skipping item - no phone numbers found");
    continue;
  }

  const primaryPhone = normalizePhone(phones[0]);

  // Skip if already processed this phone number
  if (processedPhones.has(primaryPhone)) {
    console.log(`Skipping duplicate phone: ${primaryPhone}`);
    skippedDuplicates.push(primaryPhone);
    continue;
  }

  processedPhones.add(primaryPhone);

  // Extract names
  const fullName = base.full_name || base.contact_name || 
    `${toStr(base.first_name)} ${toStr(base.last_name)}`.trim();

  let firstName = base.first_name || "";
  let lastName = base.last_name || "";

  // If no first/last name but have full name, split it
  if (!firstName && !lastName && fullName) {
    const nameParts = fullName.split(/\s+/);
    firstName = nameParts[0] || "";
    lastName = nameParts.slice(1).join(" ") || "";
  }

  // Default values if still empty
  if (!firstName && !lastName && !fullName) {
    firstName = "Unknown";
    lastName = "Contact";
  }

  const finalFullName = fullName || `${firstName} ${lastName}`.trim() || "Unknown Contact";

  // Company name
  const companyName = base.company_name || base.companyName ||
    (base.folder_name || base.folderName || "").replace(/^TAX\s+/i, "").trim() ||
    "Unknown Company";

  // Collect all phones (up to 5)
  const allPhones = uniq([
    base.phone_1,
    base.phone_2,
    base.phone_3,
    base.phone_4,
    base.phone_5,
    ...(Array.isArray(base.phone_values) ? base.phone_values : []),
    base.contact_phone
  ].filter(isNonEmpty).map(normalizePhone)).slice(0, 5);

  // Collect all emails (up to 5)
  const allEmails = uniq([
    base.email_1,
    base.email_2,
    base.email_3,
    base.email_4,
    base.email_5,
    ...(Array.isArray(base.email_values) ? base.email_values : []),
    base.contact_email
  ].filter(isNonEmpty)
    .map(e => e.toLowerCase())
    .filter(e => e.includes('@'))
  ).slice(0, 5);

  // Build custom fields array for contact
  const contactCustomFields = [];

  if (allPhones.length > 0) {
    contactCustomFields.push({
      field_code: "PHONE",
      values: allPhones.map(p => ({ 
        value: p, 
        enum_code: "WORK" 
      }))
    });
  }

  if (allEmails.length > 0) {
    contactCustomFields.push({
      field_code: "EMAIL",
      values: allEmails.map(e => ({ 
        value: e, 
        enum_code: "WORK" 
      }))
    });
  }

  // Create lead payload WITHOUT UNIQUE_ID
  const leadPayload = {
    name: finalFullName,
    pipeline_id: PIPELINE_ID,
    status_id: STATUS_ID,
    responsible_user_id: RESPONSIBLE_USER_ID,
    created_by: RESPONSIBLE_USER_ID,
    _embedded: {
      tags: FIXED_TAGS,
      companies: [{ 
        name: companyName 
      }],
      contacts: [{
        first_name: firstName || "Unknown",
        last_name: lastName || "",
        name: finalFullName,
        custom_fields_values: contactCustomFields
      }]
    }
  };

  leadsToCreate.push(leadPayload);
}

// Log summary
console.log(`=== Processing Summary ===`);
console.log(`Total items received: ${allItems.length}`);
console.log(`Unique leads to create: ${leadsToCreate.length}`);
console.log(`Duplicates skipped: ${skippedDuplicates.length}`);
if (skippedDuplicates.length > 0) {
  console.log(`Skipped phones: ${skippedDuplicates.join(", ")}`);
}

// Return for HTTP Request
return [{
  json: {
    method: "POST",
    url: `https://${SUBDOMAIN}.kommo.com/api/v4/leads/complex`,
    payload: leadsToCreate,
    summary: {
      total_items: allItems.length,
      unique_leads: leadsToCreate.length,
      duplicates_skipped: skippedDuplicates.length,
      skipped_phones: skippedDuplicates
    }
  }
}];

// n8n Function: Matching & Routing
// Input: items[].json = شكل العنصر المجمّع اللي أرسلته
// Output: عنصر واحد لكل إدخال مع route/status ورسائل وأسباب واضحة

function toStr(v){ return (v==null ? "" : String(v).trim()); }
function uniq(arr){ return Array.from(new Set((arr||[]).filter(Boolean).map(String))); }

const REQUIRED_FIELDS = ["contact_name","phone_1","email_1"]; // العناصر الثلاثة المطلوبة

function pickUniqueOrNull(arr){
  const a = uniq(arr);
  return a.length === 1 ? a[0] : null;
}

function routeDecision(entry){
  // IDs lists (as strings)
  const contactIds = uniq(entry.contact_ids || []);
  const leadIds    = uniq(entry.lead_ids    || []);
  const companyIds = uniq(entry.company_ids || []);

  const counts = {
    contact: contactIds.length,
    lead:    leadIds.length,
    company: companyIds.length,
  };

  const duplicates = {
    contacts: counts.contact > 1,
    leads:    counts.lead    > 1,
    companies:counts.company > 1,
  };

  // missing fields (from original input)
  const missingFields = REQUIRED_FIELDS.filter(k => toStr(entry[k]) === "");

  // وجود جزئي: عندي بعض الـ IDs لكن مش الكل
  const someExist = (counts.contact + counts.lead + counts.company) > 0;
  const fullExist = (counts.contact === 1 && counts.lead === 1 && counts.company === 1);

  // ألوان/إيموجيز موحدة
  const COLORS = { PASS:"#2563eb", CREATE:"#16a34a", BLOCK:"#dc2626" };
  const EMOJI  = { PASS:"🔵", CREATE:"🟢", BLOCK:"🔴" };

  // القرار:
  // 1) حالات التكرار = BLOCKED
  if (duplicates.contacts || duplicates.leads || duplicates.companies){
    const reason = [
      duplicates.contacts ? `تكرار Contacts (${contactIds.join(", ")})` : "",
      duplicates.leads    ? `تكرار Leads (${leadIds.join(", ")})`       : "",
      duplicates.companies? `تكرار Companies (${companyIds.join(", ")})`: ""
    ].filter(Boolean).join(" | ");

    return {
      route: "BLOCKED",
      status: "DUPLICATE_FOUND",
      status_color: COLORS.BLOCK,
      status_emoji: EMOJI.BLOCK,
      error_reason: reason || "تكرارات في السجلات؛ يلزم دمج/حذف قبل المتابعة.",
      duplicate_contact_ids: contactIds,
      duplicate_lead_ids: leadIds,
      duplicate_company_ids: companyIds,
      lead_id: null,
      contact_id: null,
      company_id: null,
      message_ar: "ممنوع التنفيذ — توجد تكرارات في النظام ويجب المراجعة/الدمج أولًا."
    };
  }

  // 2) نقص عناصر مطلوبة = BLOCKED
  if (missingFields.length > 0){
    return {
      route: "BLOCKED",
      status: "MISSING_FIELDS",
      status_color: COLORS.BLOCK,
      status_emoji: EMOJI.BLOCK,
      error_reason: `نقص بيانات مطلوبة: ${missingFields.join(", ")}`,
      duplicate_contact_ids: [],
      duplicate_lead_ids: [],
      duplicate_company_ids: [],
      lead_id: null,
      contact_id: null,
      company_id: null,
      message_ar: "ممنوع التنفيذ — البيانات غير مكتملة (الاسم/الهاتف/الإيميل)."
    };
  }

  // 3) موجود بالكامل وفريد = PASS_EXISTING
  if (fullExist){
    const lead_id    = leadIds[0];
    const contact_id = contactIds[0];
    const company_id = companyIds[0];
    return {
      route: "PASS_EXISTING",
      status: "SKIP_COMPLETE",
      status_color: COLORS.PASS,
      status_emoji: EMOJI.PASS,
      error_reason: "",
      duplicate_contact_ids: [],
      duplicate_lead_ids: [],
      duplicate_company_ids: [],
      lead_id,
      contact_id,
      company_id,
      message_ar: `قيد موجود فعليًا في Kommo (Lead: ${lead_id}, Contact: ${contact_id}, Company: ${company_id})`
    };
  }

  // 4) غير مسجل إطلاقًا + مكتمل البيانات = CREATE
  if (!someExist){
    return {
      route: "CREATE",
      status: "CREATE_NEW",
      status_color: COLORS.CREATE,
      status_emoji: EMOJI.CREATE,
      error_reason: "",
      duplicate_contact_ids: [],
      duplicate_lead_ids: [],
      duplicate_company_ids: [],
      lead_id: null,
      contact_id: null,
      company_id: null,
      message_ar: "عميل جديد – إنشاء سجل جديد (لا توجد سجلات مطابقة في Kommo)."
    };
  }

  // 5) تطابق جزئي (بعض IDs موجودة وليس كلها) = BLOCKED
  const details = [];
  if (counts.lead === 1 && counts.contact === 0) details.push(`يوجد Lead (${leadIds[0]}) بلا Contact/Company`);
  if (counts.contact === 1 && counts.lead === 0) details.push(`يوجد Contact (${contactIds[0]}) بلا Lead/Company`);
  if (counts.company === 1 && counts.lead === 0) details.push(`يوجد Company (${companyIds[0]}) بلا Lead`);
  if (details.length === 0){
    details.push(`تطابق جزئي: leads=${counts.lead}, contacts=${counts.contact}, companies=${counts.company}`);
  }

  return {
    route: "BLOCKED",
    status: "PARTIAL_MATCH",
    status_color: COLORS.BLOCK,
    status_emoji: EMOJI.BLOCK,
    error_reason: details.join(" | "),
    duplicate_contact_ids: [],
    duplicate_lead_ids: [],
    duplicate_company_ids: [],
    lead_id: pickUniqueOrNull(leadIds),
    contact_id: pickUniqueOrNull(contactIds),
    company_id: pickUniqueOrNull(companyIds),
    message_ar: "ممنوع التنفيذ — تطابق جزئي يلزمه دمج/تنظيف السجلات قبل المتابعة."
  };
}

return items.map(it => {
  const e = it.json || {};

  const decision = routeDecision(e);

  // خط تجميعي للأيقونة والحالة (عرض)
  const status_line = `${decision.status_emoji} | ${decision.status} | ${decision.message_ar}`;

  // توحيد كل IDs لسهولة التصدير
  const ids_all = []
    .concat(decision.lead_id ? [String(decision.lead_id)] : [])
    .concat(decision.contact_id ? [String(decision.contact_id)] : [])
    .concat(decision.company_id ? [String(decision.company_id)] : [])
    .concat(decision.duplicate_lead_ids || [])
    .concat(decision.duplicate_contact_ids || [])
    .concat(decision.duplicate_company_ids || []);

  return {
    json: {
      // مدخلاتك الأصلية المهمة لسهولة التتبع
      phone_query: e.phone_query || "",
      contact_name: toStr(e.contact_name || ""),
      company_name: toStr(e.company_name || ""),
      folder_name:  toStr(e.folder_name  || ""),
      folder_Id:    toStr(e.folder_Id    || ""),
      phone_1:      toStr(e.phone_1      || ""),
      email_1:      toStr(e.email_1      || ""),
      primary_query_type: e.primary_query_type || "",
      primary_query_value: e.primary_query_value || "",
      batch_date: e.batch_date || "",
      batch_time: e.batch_time || "",

      // قرار المطابقة
      route: decision.route,
      status: decision.status,
      status_line,
      status_color: decision.status_color,
      status_emoji: decision.status_emoji,
      error_reason: decision.error_reason,

      // IDs مختارة إن كانت فريدة
      lead_id: decision.lead_id,
      contact_id: decision.contact_id,
      company_id: decision.company_id,

      // كل التكرارات إن وجدت
      duplicate_lead_ids: decision.duplicate_lead_ids,
      duplicate_contact_ids: decision.duplicate_contact_ids,
      duplicate_company_ids: decision.duplicate_company_ids,

      // لسهولة التصدير/العرض
      ids_all,

      // إرجاع التجميعات/العدادات كما هي (اختياري)
      lead_ids: uniq(e.lead_ids || []),
      contact_ids: uniq(e.contact_ids || []),
      company_ids: uniq(e.company_ids || []),
      lead_count: e.lead_count || (e.lead_ids || []).length || 0,
      contact_count: e.contact_count || (e.contact_ids || []).length || 0,
      company_count: e.company_count || (e.company_ids || []).length || 0,

      // التفاصيل الأصلية من تجميعة الكونتاكتس (لو حبيت تعرضها)
      contacts: e.contacts || []
    }
  };
});

// ======================================
// كود المطابقة الذكية - نسخة محسّنة ودقيقة
// ======================================

// -------- دوال المساعدة --------

/**
 * تنظيف وتوحيد النص
 */
function normalizeText(text) {
  if (!text) return "";

  let t = String(text)
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();

  // توحيد مسافات ورموز
  t = t.replace(/[_\-–—\.]+/g, " ").replace(/\s+/g, " ").trim();

  // تطبيع الحروف التركية
  const turkishMap = {
    'ı': 'i', 'İ': 'i',
    'ş': 's', 'Ş': 's', 
    'ğ': 'g', 'Ğ': 'g',
    'ç': 'c', 'Ç': 'c',
    'ö': 'o', 'Ö': 'o',
    'ü': 'u', 'Ü': 'u'
  };

  for (const [from, to] of Object.entries(turkishMap)) {
    t = t.replace(new RegExp(from, 'g'), to);
  }

  return t;
}

/**
 * إزالة البادئات الخاصة والحالات القانونية
 */
function cleanSpecialPrefixes(name) {
  let n = normalizeText(name);

  // إزالة حالات التصفية
  const liquidationPatterns = [
    /^tasf\.?\s*hal\.?\s*/i,
    /^tasfiye\s+halinde\s*/i,
    /^tasfiyede\s*/i,
    /^tas\.?\s*hal\.?\s*/i,
  ];

  for (const pattern of liquidationPatterns) {
    n = n.replace(pattern, "").trim();
  }

  // إزالة كلمة TAX من البداية
  n = n.replace(/^tax\s+/i, "").trim();

  return n;
}

/**
 * استخراج اسم الشركة من اسم الملف
 */
function extractCompanyNameFromFileName(fileName) {
  if (!fileName) return "";

  let name = fileName;

  // إزالة امتداد الملف
  name = name.replace(/\.(pdf|xlsx|xls|doc|docx)$/i, "").trim();

  // إزالة التواريخ والأشهر
  const months = [
    "ocak", "şubat", "mart", "nisan", "mayıs", "haziran",
    "temmuz", "ağustos", "eylül", "ekim", "kasım", "aralık",
    "january", "february", "march", "april", "may", "june",
    "july", "august", "september", "october", "november", "december"
  ];

  for (const month of months) {
    const regex = new RegExp(`\\s+${month}\\s+\\d{4}`, "gi");
    name = name.replace(regex, "");
  }

  // إزالة السنوات
  name = name.replace(/\s+\d{4}\s*/g, " ");

  // إزالة أنواع المستندات
  const docTypes = ["kdv", "kdv2", "sgk", "thk", "muhtasar", "muhsgk", "tahakkuk", "beyanname", "hizmet listesi", "vergisi", "emekli", "xml", "aylik"];
  for (const docType of docTypes) {
    const regex = new RegExp(`\\s+${docType}\\b`, "gi");
    name = name.replace(regex, "");
  }

  // إزالة الأرقام والرموز الزائدة
  name = name.replace(/\s+\d+\s*/g, " ");
  name = name.replace(/[_\-–—\(\)]+/g, " ");

  return name.trim();
}

/**
 * إزالة اللواحق من نهاية أسماء الشركات
 */
function stripCompanySuffixes(name) {
  let n = normalizeText(name);

  // إزالة اللواحق بالترتيب من الأطول للأقصر
  const suffixesToRemove = [
    // عبارات طويلة
    "sanayi ticaret anonim sirketi",
    "ic ve dis ticaret limited sirketi",
    "ithalat ve ihracat limited sirketi",
    "ithalat ihracat limited sirketi",
    "ic ve dis ticaret",
    "ithalat ve ihracat",
    "ithalat ihracat",
    "sanayi ticaret",
    "dis ticaret",
    "limited sirketi",
    "anonim sirketi",

    // كلمات مفردة
    "gayrimenkul", "realestate", "realstate",
    "anonim", "limited", "sirketi",
    "ticaret", "sanayi", "ithalat", "ihracat", "lojistik",
    "danismanlik", "hizmet", "yatirim", "yapimi",
    "ltd", "sti", "as", "a.s", "a.s.",

    // كلمات ربط
    "ve", "and"
  ];

  for (const suffix of suffixesToRemove) {
    const pattern = new RegExp(`\\s+${suffix}\\s*$`, 'gi');
    n = n.replace(pattern, "").trim();
  }

  return n.trim();
}

/**
 * حساب مسافة التحرير (Levenshtein Distance)
 */
function editDistance(s1, s2) {
  const len1 = s1.length;
  const len2 = s2.length;

  const matrix = Array(len1 + 1).fill(null).map(() => Array(len2 + 1).fill(0));

  for (let i = 0; i <= len1; i++) matrix[i][0] = i;
  for (let j = 0; j <= len2; j++) matrix[0][j] = j;

  for (let i = 1; i <= len1; i++) {
    for (let j = 1; j <= len2; j++) {
      const cost = s1[i - 1] === s2[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost
      );
    }
  }

  return matrix[len1][len2];
}

/**
 * حساب نسبة التشابه
 */
function similarityScore(s1, s2) {
  const maxLen = Math.max(s1.length, s2.length);
  if (maxLen === 0) return 1.0;

  const distance = editDistance(s1, s2);
  return 1 - (distance / maxLen);
}

/**
 * ✅ التحقق من تطابق الكلمة الأولى (قاعدة الأمان)
 */
function hasFirstWordMatch(name1, name2) {
  const words1 = stripCompanySuffixes(normalizeText(name1)).split(/\s+/).filter(w => w.length > 2);
  const words2 = stripCompanySuffixes(normalizeText(name2)).split(/\s+/).filter(w => w.length > 2);

  if (words1.length === 0 || words2.length === 0) return false;

  // يجب أن تتطابق الكلمة الأولى على الأقل
  return words1[0] === words2[0];
}

/**
 * المطابقة الذكية المحسّنة مع قواعد الأمان
 */
function smartMatch(name1, name2) {
  // تنظيف الأسماء
  const clean1 = cleanSpecialPrefixes(name1);
  const clean2 = cleanSpecialPrefixes(name2);

  // تطبيع كامل
  const norm1 = normalizeText(clean1);
  const norm2 = normalizeText(clean2);

  // إزالة اللواحق
  const stripped1 = stripCompanySuffixes(clean1);
  const stripped2 = stripCompanySuffixes(clean2);

  // 1. تطابق تام
  if (norm1 === norm2 || stripped1 === stripped2) {
    return 1.0;
  }

  // 2. أحدهما يبدأ بالآخر
  if (norm1.startsWith(norm2) || norm2.startsWith(norm1)) {
    return 0.95;
  }
  if (stripped1.startsWith(stripped2) || stripped2.startsWith(stripped1)) {
    return 0.93;
  }

  // 3. أحدهما يحتوي الآخر
  if (norm1.includes(norm2) || norm2.includes(norm1)) {
    return 0.90;
  }
  if (stripped1.includes(stripped2) || stripped2.includes(stripped1)) {
    return 0.88;
  }

  // ✅ قاعدة الأمان: يجب أن تتطابق الكلمة الأولى
  if (!hasFirstWordMatch(name1, name2)) {
    return 0; // رفض المطابقة تماماً
  }

  // 4. مطابقة الكلمات الأساسية
  const words1 = stripped1.split(/\s+/).filter(w => w.length > 2);
  const words2 = stripped2.split(/\s+/).filter(w => w.length > 2);

  if (words1.length > 0 && words2.length > 0) {
    let matchedWords = 0;

    for (const w1 of words1) {
      for (const w2 of words2) {
        if (w1 === w2) {
          matchedWords += 1.0;
          break;
        }
        const wordSim = similarityScore(w1, w2);
        if (wordSim >= 0.85) {
          matchedWords += wordSim;
          break;
        }
      }
    }

    const wordScore = matchedWords / Math.max(words1.length, words2.length);
    if (wordScore >= 0.6) {
      return 0.70 + (wordScore * 0.15);
    }
  }

  // 5. مقارنة التشابه العام
  const overallSim1 = similarityScore(norm1, norm2);
  const overallSim2 = similarityScore(stripped1, stripped2);
  const maxSim = Math.max(overallSim1, overallSim2);

  if (maxSim >= 0.65) {
    return maxSim * 0.85;
  }

  return 0;
}

/**
 * استخراج جميع المعرفات الممكنة من البيانات
 */
function extractCompanyIdentifiers(data, isFile = false) {
  const identifiers = [];

  if (isFile && data.fileName) {
    const fromFileName = extractCompanyNameFromFileName(data.fileName);
    if (fromFileName) {
      identifiers.push(fromFileName);

      const cleaned = cleanSpecialPrefixes(fromFileName);
      if (cleaned && cleaned !== fromFileName) {
        identifiers.push(cleaned);
      }

      const stripped = stripCompanySuffixes(fromFileName);
      if (stripped && stripped !== cleaned) {
        identifiers.push(stripped);
      }
    }
  }

  const possibleFields = [
    'companyName', 'Company Name', 'company_name',
    'taxFolderName', 'Tax Folder Name', 
    'name', 'Name', 'title', 'Title'
  ];

  for (const field of possibleFields) {
    if (data[field]) {
      const value = String(data[field]).trim();
      if (value) {
        const cleaned = cleanSpecialPrefixes(value);
        identifiers.push(cleaned);

        const stripped = stripCompanySuffixes(cleaned);
        if (stripped && stripped !== cleaned) {
          identifiers.push(stripped);
        }

        const normalized = normalizeText(cleaned);
        if (normalized && normalized !== cleaned) {
          identifiers.push(normalized);
        }
      }
    }
  }

  return [...new Set(identifiers)].filter(Boolean);
}

