  console.log(`\nCompany: ${company.companyName}`);
  console.log(`  Tax Type: ${taxType}`);
  console.log(`  Month: ${month}`);

  // 1. البحث عن tag يطابق نوع الضريبة + الشهر
  const primaryTagName = `${taxType}_${month}`;
  if (tagLookup[primaryTagName]) {
    matchedTags.push(tagLookup[primaryTagName]);
    matchedTagIds.push(tagLookup[primaryTagName].id);
    matchedTagNames.push(tagLookup[primaryTagName].name);
    console.log(`  Found primary tag: ${primaryTagName} (ID: ${tagLookup[primaryTagName].id})`);
  }

  // 2. البحث عن tag بديل (بدون underscore)
  const altTagName = `${taxType}-${month}`;
  if (tagLookup[altTagName] && !matchedTagIds.includes(tagLookup[altTagName].id)) {
    matchedTags.push(tagLookup[altTagName]);
    matchedTagIds.push(tagLookup[altTagName].id);
    matchedTagNames.push(tagLookup[altTagName].name);
    console.log(`  Found alt tag: ${altTagName} (ID: ${tagLookup[altTagName].id})`);
  }

  // 3. البحث عن tag مع رقم 2 (KDV2)
  if (taxType.includes("KDV")) {
    const kdv2TagName = `KDV2_${month}`;
    if (tagLookup[kdv2TagName] && !matchedTagIds.includes(tagLookup[kdv2TagName].id)) {
      matchedTags.push(tagLookup[kdv2TagName]);
      matchedTagIds.push(tagLookup[kdv2TagName].id);
      matchedTagNames.push(tagLookup[kdv2TagName].name);
      console.log(`  Found KDV2 tag: ${kdv2TagName} (ID: ${tagLookup[kdv2TagName].id})`);
    }
  }

  // 4. معالجة STOPAJ
  if (taxType.includes("STOPAJ")) {
    const stopajTagName = `STOPAJ_${month}`;
    if (tagLookup[stopajTagName] && !matchedTagIds.includes(tagLookup[stopajTagName].id)) {
      matchedTags.push(tagLookup[stopajTagName]);
      matchedTagIds.push(tagLookup[stopajTagName].id);
      matchedTagNames.push(tagLookup[stopajTagName].name);
      console.log(`  Found STOPAJ tag: ${stopajTagName} (ID: ${tagLookup[stopajTagName].id})`);
    }
  }

  // 5. معالجة KURUMLAR
  if (taxType.includes("KURUMLAR")) {
    const kurumlarTagName = `KURUMLAR_${month}`;
    if (tagLookup[kurumlarTagName] && !matchedTagIds.includes(tagLookup[kurumlarTagName].id)) {
      matchedTags.push(tagLookup[kurumlarTagName]);
      matchedTagIds.push(tagLookup[kurumlarTagName].id);
      matchedTagNames.push(tagLookup[kurumlarTagName].name);
      console.log(`  Found KURUMLAR tag: ${kurumlarTagName} (ID: ${tagLookup[kurumlarTagName].id})`);
    }

    // ضريبة الشركات السنوية
    if (month === "ARALIK" && tagLookup["YILLIK"]) {
      matchedTags.push(tagLookup["YILLIK"]);
      matchedTagIds.push(tagLookup["YILLIK"].id);
      matchedTagNames.push(tagLookup["YILLIK"].name);
      console.log(`  Found yearly tag: YILLIK (ID: ${tagLookup["YILLIK"].id})`);
