  };
}

// دالة لمعالجة Lead IDs المتعددة
function processLeadIds(leadIdRaw) {
  let leadIds = [];

  if (!leadIdRaw) {
    return leadIds;
  }

  // التحقق من نوع البيانات
  if (typeof leadIdRaw === 'string') {
    // فصل القيم المتعددة بالفاصلة أو المسافة أو الفاصلة المنقوطة
    leadIds = leadIdRaw
      .split(/[,;\s]+/)
      .map(id => id.trim())
      .filter(id => id && id !== "" && id !== "0" && !isNaN(id));
  } else if (typeof leadIdRaw === 'number') {
    if (leadIdRaw > 0) {
      leadIds = [String(leadIdRaw)];
    }
  } else if (Array.isArray(leadIdRaw)) {
    leadIds = leadIdRaw
      .map(id => String(id).trim())
      .filter(id => id && id !== "" && id !== "0" && !isNaN(id));
  }

  // إزالة المكررات
  return [...new Set(leadIds)];
}

