const items = $input.all();

/* ======================= Helpers ======================= */

const normalize = (str = "") =>
  str.toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/ı/g, "i")
    .replace(/ş/g, "s")
    .replace(/ğ/g, "g")
    .replace(/ç/g, "c")
    .replace(/ö/g, "o")
    .replace(/ü/g, "u")
    .replace(/\s+/g, " ")
    .trim();

const monthNameTR = (mm) => ({
  "01":"Ocak","02":"Şubat","03":"Mart","04":"Nisan","05":"Mayıs","06":"Haziran",
  "07":"Temmuz","08":"Ağustos","09":"Eylül","10":"Ekim","11":"Kasım","12":"Aralık"
}[mm] || null);

/**
 * إزالة حالات التصفية والبادئات الخاصة
 */
const removeLiquidationStatus = (name = "") => {
  if (!name) return name;

  let cleaned = name.trim();

  // أنماط حالات التصفية المختلفة
  const liquidationPatterns = [
    /^TASF\.?\s*HAL\.?\s*/i,           // TASF.HAL. أو TASF HAL
    /^TASFİYE\s+HALİNDE\s*/i,          // TASFİYE HALİNDE
    /^TASFİYEDE\s*/i,                  // TASFİYEDE
    /^TAS\.?\s*HAL\.?\s*/i,            // TAS.HAL
    /^T\.H\.\s*/i,                     // T.H.
    /^LIQUIDATION\s*/i,                // LIQUIDATION
    /^IN\s+LIQUIDATION\s*/i,           // IN LIQUIDATION
    /^LİKİDASYON\s*/i,                 // LİKİDASYON
    /^FESİH\s+HALİNDE\s*/i,            // FESİH HALİNDE (في حالة الإلغاء)
  ];

  // إزالة حالات التصفية
  for (const pattern of liquidationPatterns) {
    cleaned = cleaned.replace(pattern, "").trim();
  }

  // إزالة النقاط المتبقية من البداية
  cleaned = cleaned.replace(/^\.+/, "").trim();

  return cleaned;
};

/**
 * تنظيف الاسم من الكلمات الزائدة والعناوين مع الحفاظ على حالات التصفية
 */
const cleanCompanyName = (raw = "") => {
  if (!raw) return null;

  let cleaned = raw.trim();

  // إزالة حالات التصفية أولاً
  cleaned = removeLiquidationStatus(cleaned);

  // إزالة العناوين والأرقام الطويلة
  cleaned = cleaned.replace(/\b\d{10,}\b/g, ""); // إزالة الأرقام الطويلة جداً
  cleaned = cleaned.replace(/\d{6,}-\d+\/\d+/g, ""); // إزالة أرقام السجل
  cleaned = cleaned.replace(/\b\d{4}\/\d{2}\/\d{4}\b/g, ""); // إزالة التواريخ

  // إزالة المسارات والعناوين
  const addressPatterns = [
    /BEŞYOL\s+MAH[\s\S]*?KÜÇÜKÇEKMECE/gi,
    /\bMAH\.?\s+[^,\n]*/gi,
    /\bSK\.?\s+[^,\n]*/gi,
    /\bCAD\.?\s+[^,\n]*/gi,
    /\bBLV\.?\s+[^,\n]*/gi,
    /Dış\s+kapı\s+no:\d+/gi,
    /İç\s+kapı\s+no:\d+/gi,
    /Kapı\s+No:\d+/gi,
    /Daire\s+No:\d+/gi
  ];

  for (const pattern of addressPatterns) {
    cleaned = cleaned.replace(pattern, " ");
  }

  // إزالة أسماء المدن
  const cities = [
    "İSTANBUL", "KÜÇÜKÇEKMECE", "BEYLİKDÜZÜ", "BAŞAKŞEHİR",
    "BAHÇELİEVLER", "ESENYURT", "ÜMRANİYE", "AVCILAR"
  ];

  for (const city of cities) {
    cleaned = cleaned.replace(new RegExp(`\\b${city}\\b`, 'gi'), "");
  }

  // تنظيف نهائي
  cleaned = cleaned
    .replace(/[\/\-–—,;:|()]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  return cleaned.length > 2 ? cleaned : null;
};

/* ========== Extract Company Name (enhanced for liquidation cases) ========== */

const extractCompanyFromText = (text = "", fileName = "") => {
  if (!text) return null;

  const lines = text.split(/\r?\n/).map(l => l.trim()).filter(Boolean);

  // === حالة 1: وثائق SGK - البحث عن Unvanı متبوعاً باسم الشركة ===
  for (let i = 0; i < lines.length - 5; i++) {
    const line = lines[i];

    // البحث عن سطر يحتوي على كلمة Unvanı فقط أو مع نقطتين
    if (line.match(/^Unvanı\s*:?\s*$/i)) {
      // البحث في الأسطر التالية عن اسم الشركة
      for (let j = 1; j <= 5; j++) {
        const nextLine = lines[i + j];
        if (!nextLine) continue;

        // تجنب الأسطر التي تحتوي على معلومات أخرى
        if (nextLine.match(/^(ADRES|BEŞ|YAK|GÜL|MEH|NAM|CUM|İKİ|HÜR|PİR)/i)) continue;
        if (nextLine.match(/^\d{6,}/)) continue; // أرقام طويلة
        if (nextLine.match(/^\d+\s*\/\s*/)) continue; // تواريخ أو أرقام

        // البحث عن أسماء الشركات بالكلمات المفتاحية
        if (nextLine.match(/(ŞİRKET|TİCARET|SANAYİ|LOJİSTİK|PERAKENDE|İTHALAT|İHRACAT|LİMİTED|LTD|GROUP|PLATFORM|MEDİKAL|DANIŞMANLIK|OTOMOTİV|GAYRİMENKUL|ARAÇ|MEDYA|BUSINESS|EXPERTS)/i)) {
          const cleaned = cleanCompanyName(nextLine);
          if (cleaned && cleaned.length > 5) {
            return cleaned;
          }
        }

        // إذا كان السطر يبدأ بحالة تصفية، نعالجه أيضاً
        if (nextLine.match(/^(TASF|TASFİYE|LİKİDASYON)/i)) {
          const cleaned = cleanCompanyName(nextLine);
          if (cleaned && cleaned.length > 5) {
            return cleaned;
          }
        }
      }
    }
  }

  // === حالة 2: وثائق الضرائب - SOYADI (UNVANI) NAME ===
  for (let i = 0; i < lines.length - 1; i++) {
    const line = lines[i];

    // Pattern: SOYADI (UNVANI) COMPANY_NAME
    const pattern1 = /^SOYADI\s*\(\s*UNVANI\s*\)\s+(.+)$/i;
    const match1 = line.match(pattern1);
    if (match1 && match1[1]) {
      let companyName = match1[1].trim();

      // إزالة حالة التصفية إن وجدت
      companyName = removeLiquidationStatus(companyName);

      // إذا كان اسم شخص (كلمة واحدة)، ابحث عن الاسم الأول
      if (!companyName.includes(" ") && i + 1 < lines.length) {
        const nextLine = lines[i + 1];
        if (nextLine.match(/^ADI\s+(.+)$/i)) {
          const firstName = nextLine.replace(/^ADI\s+/i, "").trim();
          return `${firstName} ${companyName}`.trim();
        }
      }

      // إذا كان اسم شركة
      if (companyName.match(/(TİCARET|ŞİRKET|LİMİTED|İTHALAT|İHRACAT|LOJİSTİK|PLATFORM|GROUP)/i) || 
          companyName.length > 5) {
        return companyName;
      }

      // إرجاع الاسم كما هو
      return companyName;
    }

    // Pattern: SOYADI (UNVANI) متبوع بالاسم في السطر التالي
    if (line.match(/^SOYADI\s*\(\s*UNVANI\s*\)\s*$/i) && i + 1 < lines.length) {
      let nextLine = lines[i + 1];

      // إزالة حالة التصفية إن وجدت
      nextLine = removeLiquidationStatus(nextLine);

      if (!nextLine.match(/^(ADI|KABUL|VERGİ|ADRES)/i) && nextLine.length > 2) {
        return nextLine.trim();
      }
    }
  }

  // === حالة 3: İşyeri Ünvanı ===
  for (let i = 0; i < lines.length - 1; i++) {
    const line = lines[i];

    if (line.match(/^İşyeri\s+Ünvanı\s*:?\s*$/i)) {
      // الاسم في السطر التالي
      for (let j = 1; j <= 3; j++) {
        let nextLine = lines[i + j];
        if (!nextLine) continue;

        // إزالة حالة التصفية أولاً
        const cleanedLine = removeLiquidationStatus(nextLine);

        // تجنب العناوين
        if (cleanedLine.match(/^(BEŞYOL|YAKUPLU|GÜLTEPE|MEHMET|NAMIK|CUMHURİYET|İKİTELLİ|HÜRRİYET|PİRİ)/i)) continue;

        // إذا وجدنا اسم شركة
        if (cleanedLine.length > 5 && !cleanedLine.match(/^\d/)) {
          const finalCleaned = cleanCompanyName(nextLine); // نمرر النص الأصلي للتنظيف الكامل
          if (finalCleaned && finalCleaned.length > 5) {
            return finalCleaned;
          }
        }
      }
    }
  }

  // === حالة 4: البحث العام عن أسماء الشركات ===
  const companyKeywords = [
    "ŞİRKETİ", "ŞİRKET", "TİCARET", "SANAYİ", "LOJİSTİK",
    "İTHALAT", "İHRACAT", "LİMİTED", "LTD", "ANONİM",
    "DANIŞMANLIK", "MEDİKAL", "MEDYA", "GROUP", "BUSINESS",
    "PLATFORM", "OTOMOTİV", "GAYRİMENKUL", "PERAKENDE", "ARAÇ",
    "CURE", "ALOSS", "EXPERTS", "OVERSEAS"
  ];

  for (const line of lines) {
    // تجنب أسطر العناوين
    if (line.match(/^(T\.C\.|VERGİ|TAHAKKUK|ADRES|MAKİNA|KABUL|SOYADI|ADI\s|Unvanı)/i)) continue;

    // تنظيف السطر من حالات التصفية
    const cleanedLine = removeLiquidationStatus(line);

    for (const keyword of companyKeywords) {
      if (cleanedLine.toUpperCase().includes(keyword)) {
        const finalCleaned = cleanCompanyName(line);
        if (finalCleaned && finalCleaned.length > 10 && !finalCleaned.match(/^(UNVANI|ADI|SOYADI)/i)) {
          return finalCleaned;
        }
      }
    }
  }

  return null;
};

/* ========== Extract Document Type ========== */

const extractDocumentType = (text = "", fileName = "") => {
  const nText = normalize(text);
  const nName = normalize(fileName);

  // SGK وثائق - نوع واحد فقط
  if (nText.includes("sosyal guvenlik kurumu") || 
      nText.includes("sigorta primleri genel") ||
      nText.includes("sigortali hizmet listesi")) {
    return "SGK";
  }

  // KDV وثائق
  if (nText.includes("katma deger vergisi tevkifati")) {
    return "KDV Tevkifat";
  }
  if (nText.includes("katma deger vergisi") || nText.includes("kdv")) {
    return "KDV";
  }

  // ضريبة الدخل والاستقطاع - فقط Muhtasar
  if (nText.includes("gelir vergisi") && nText.includes("muhtasar")) {
    return "Muhtasar";
  }
  if (nText.includes("muhtasar")) {
    return "Muhtasar";
  }

  // ضريبة الشركات
  if (nText.includes("kurum gecici vergi")) {
    return "Kurumlar Geçici";
  }
  if (nText.includes("kurumlar vergisi") || nText.includes("kurum vergisi")) {
    return "Kurumlar";
  }

  // التحقق من رمز الضريبة
  const taxCodeMatch = text.match(/Ana\s+Vergi\s+Kodu\s+0*([0-9]+)/i);
  if (taxCodeMatch) {
    const code = taxCodeMatch[1];
    switch(code) {
      case "3": return "Muhtasar";
      case "10": return "Kurumlar";
      case "15": return "KDV";
      case "33": return "Kurumlar Geçici";
      case "4017": return "KDV Tevkifat";
      default: return `Vergi Kodu ${code}`;
    }
  }

  return "Bilinmeyen";
};

/* ========== Extract Period ========== */

const extractPeriod = (text = "", fileName = "") => {
  const all = `${text}\n${fileName}`;

  // Pattern 1: AİT OLDUĞU YIL / AY (SGK format)
  let match = all.match(/AİT\s+OLDUĞU\s+YIL\s*\/\s*AY[^0-9]*(\d{4})\/(\d{2})/i);
  if (match) {
    return { 
      monthNumber: match[2], 
      monthName: monthNameTR(match[2]), 
      year: match[1] 
    };
  }

  // Pattern 2: Direct year/month pattern in SGK documents
  match = all.match(/(\d{4})\/(\d{2})\s*$/m);
  if (match) {
    return { 
      monthNumber: match[2], 
      monthName: monthNameTR(match[2]), 
      year: match[1] 
    };
  }

  // Pattern 3: Vergilendirme Dönemi
  match = all.match(/Vergilendirme\s+Dönemi[^0-9]*(\d{2})\/(\d{4})/i);
  if (match) {
    return { 
      monthNumber: match[1], 
      monthName: monthNameTR(match[1]), 
      year: match[2] 
    };
  }

  // Pattern 4: Yıl - Ay (alternative SGK format)
  match = all.match(/Yıl\s*-\s*Ay[^0-9]*(\d{4})\/(\d{2})/i);
  if (match) {
    return { 
      monthNumber: match[2], 
      monthName: monthNameTR(match[2]), 
      year: match[1] 
    };
  }

  // Pattern 5: Date range (04/2025-06/2025)
  match = all.match(/(\d{2})\/(\d{4})\s*-\s*(\d{2})\/(\d{4})/);
  if (match) {
    // نأخذ التاريخ النهائي
    return { 
      monthNumber: match[3], 
      monthName: monthNameTR(match[3]), 
      year: match[4] 
    };
  }

  // Pattern 6: Simple date MM/YYYY
  match = all.match(/(\d{2})\/(\d{4})/);
  if (match && parseInt(match[1]) <= 12) {
    return { 
      monthNumber: match[1], 
      monthName: monthNameTR(match[1]), 
      year: match[2] 
    };
  }

  return { 
    monthNumber: null, 
    monthName: null, 
    year: null 
  };
};

/* ========== Extract Total Amount ========== */

const parseTurkishAmount = (s) => {
  if (!s) return null;
  let cleaned = s.replace(/\s/g, "");
  cleaned = cleaned.replace(/\./g, "").replace(/,/, ".");
  const value = parseFloat(cleaned);
  return isNaN(value) ? null : value;
};

const extractTotalAmount = (text = "") => {
  if (!text) return null;

  // أنماط خاصة بـ SGK
  const sgkPatterns = [
    { regex: /ÖDENECEK\s+NET\s+TUTAR\s+([0-9.,\s]+)/gi, priority: 1 },
    { regex: /NET\s+PRİM\s+TUTARI\s+([0-9.,\s]+)/gi, priority: 2 },
    { regex: /TOPLAM\s+PRİM\s+([0-9.,\s]+)/gi, priority: 2 },
    { regex: /İŞSİZLİK\s+TUTARI[^0-9]*([0-9.,\s]+)/gi, priority: 3 },
  ];

  // أنماط عامة للضرائب الأخرى
  const generalPatterns = [
    { regex: /TOPLAM\s+([0-9.,\s]+)/gi, priority: 1 },
    { regex: /ÖDENECEK\s+OLAN[^0-9]*([0-9.,\s]+)/gi, priority: 2 },
  ];

  // تحديد نوع الوثيقة
  const isSGK = text.includes("SOSYAL GÜVENLİK KURUMU");
  const patterns = isSGK ? [...sgkPatterns, ...generalPatterns] : [...generalPatterns, ...sgkPatterns];

  const amounts = [];

  for (const { regex, priority } of patterns) {
    let match;
    regex.lastIndex = 0;
    while ((match = regex.exec(text)) !== null) {
      if (match[1]) {
        const amount = parseTurkishAmount(match[1]);
        if (amount !== null && amount > 0) {
          amounts.push({ value: amount, priority });
        }
      }
    }
  }

  // في وثائق SGK، ابحث عن السطر الأخير الذي يحتوي على رقم
  if (isSGK && amounts.length > 0) {
    // البحث عن آخر قيمة رقمية كبيرة في النص
    const lastNumberPattern = /([0-9]+\.?[0-9]*,\d{2})\s*$/gm;
    let lastMatch;
    let match;
    while ((match = lastNumberPattern.exec(text)) !== null) {
      lastMatch = match;
    }
    if (lastMatch && lastMatch[1]) {
      const lastAmount = parseTurkishAmount(lastMatch[1]);
      if (lastAmount && lastAmount > 100) { // فقط المبالغ الكبيرة
        amounts.push({ value: lastAmount, priority: 0 }); // أعلى أولوية
      }
    }
  }

  if (amounts.length > 0) {
    amounts.sort((a, b) => {
      if (a.priority !== b.priority) return a.priority - b.priority;
      return b.value - a.value;
    });
    return amounts[0].value;
  }

  return null;
};

