  const d = item.json || {};
  const records = Array.isArray(d.all_records) ? d.all_records : [d];
  const base = records[0] || {};

  // Extract primary phone for duplicate checking
  const phones = [
    base.phone_1,
    base.phone_2,
    base.phone_values?.[0],
    base.contact_phone
  ].filter(p => p && p.toString().trim());

  if (phones.length === 0) {
    console.log("Skipping item - no phone numbers found");
    continue;
  }

  const primaryPhone = normalizePhone(phones[0]);

  // Skip if already processed this phone number
  if (processedPhones.has(primaryPhone)) {
    console.log(`Skipping duplicate phone: ${primaryPhone}`);
    skippedDuplicates.push(primaryPhone);
    continue;
  }

  processedPhones.add(primaryPhone);

  // Extract names
  const fullName = base.full_name || base.contact_name || 
    `${toStr(base.first_name)} ${toStr(base.last_name)}`.trim();

  let firstName = base.first_name || "";
  let lastName = base.last_name || "";

  // If no first/last name but have full name, split it
  if (!firstName && !lastName && fullName) {
    const nameParts = fullName.split(/\s+/);
    firstName = nameParts[0] || "";
    lastName = nameParts.slice(1).join(" ") || "";
  }

  // Default values if still empty
  if (!firstName && !lastName && !fullName) {
    firstName = "Unknown";
    lastName = "Contact";
  }

  const finalFullName = fullName || `${firstName} ${lastName}`.trim() || "Unknown Contact";

  // Company name
  const companyName = base.company_name || base.companyName ||
    (base.folder_name || base.folderName || "").replace(/^TAX\s+/i, "").trim() ||
    "Unknown Company";

  // Collect all phones (up to 5)
  const allPhones = uniq([
    base.phone_1,
    base.phone_2,
    base.phone_3,
    base.phone_4,
    base.phone_5,
    ...(Array.isArray(base.phone_values) ? base.phone_values : []),
    base.contact_phone
  ].filter(isNonEmpty).map(normalizePhone)).slice(0, 5);

  // Collect all emails (up to 5)
  const allEmails = uniq([
    base.email_1,
    base.email_2,
    base.email_3,
    base.email_4,
    base.email_5,
    ...(Array.isArray(base.email_values) ? base.email_values : []),
    base.contact_email
  ].filter(isNonEmpty)
    .map(e => e.toLowerCase())
    .filter(e => e.includes('@'))
  ).slice(0, 5);

  // Build custom fields array for contact
  const contactCustomFields = [];

  if (allPhones.length > 0) {
    contactCustomFields.push({
      field_code: "PHONE",
      values: allPhones.map(p => ({ 
        value: p, 
        enum_code: "WORK" 
      }))
    });
  }

  if (allEmails.length > 0) {
    contactCustomFields.push({
      field_code: "EMAIL",
      values: allEmails.map(e => ({ 
        value: e, 
        enum_code: "WORK" 
      }))
    });
  }

  // Create lead payload WITHOUT UNIQUE_ID
  const leadPayload = {
    name: finalFullName,
    pipeline_id: PIPELINE_ID,
    status_id: STATUS_ID,
    responsible_user_id: RESPONSIBLE_USER_ID,
    created_by: RESPONSIBLE_USER_ID,
    _embedded: {
      tags: FIXED_TAGS,
      companies: [{ 
        name: companyName 
      }],
      contacts: [{
        first_name: firstName || "Unknown",
        last_name: lastName || "",
        name: finalFullName,
        custom_fields_values: contactCustomFields
      }]
    }
  };

  leadsToCreate.push(leadPayload);
}

// Log summary
console.log(`=== Processing Summary ===`);
console.log(`Total items received: ${allItems.length}`);
console.log(`Unique leads to create: ${leadsToCreate.length}`);
console.log(`Duplicates skipped: ${skippedDuplicates.length}`);
if (skippedDuplicates.length > 0) {
  console.log(`Skipped phones: ${skippedDuplicates.join(", ")}`);
}

// Return for HTTP Request
return [{
  json: {
    method: "POST",
    url: `https://${SUBDOMAIN}.kommo.com/api/v4/leads/complex`,
    payload: leadsToCreate,
    summary: {
      total_items: allItems.length,
      unique_leads: leadsToCreate.length,
      duplicates_skipped: skippedDuplicates.length,
      skipped_phones: skippedDuplicates
    }
  }
}];

// ========================================
// Kommo Complex Add (POST /api/v4/leads/complex)
// - Works only for CREATE_FLOW items
// - Local dedupe by phone
// - Adds request_id to map API response back
// - Chunks of 50 per request (Kommo limit)
// ========================================

const SUBDOMAIN = "infodvnlogcom";
const PIPELINE_ID = 11613083;
const STATUS_ID = 89191851;
const RESPONSIBLE_USER_ID = 12924735;
const FIXED_TAGS = [{ name: "MonthlyTax" }];

const isNonEmpty = v => v != null && String(v).trim() !== "";
const toStr = v => (v == null ? "" : String(v)).trim();
const uniq = arr => [...new Set(arr.filter(isNonEmpty))];
const normalizePhone = p => toStr(p).replace(/[^\d+]+/g, "");

// خُد كل العناصر الجاية من السويتش لكن اشتغل فقط على unified_flow = CREATE_FLOW
const inputItems = $input.all()
  .map(i => i.json || {})
  .filter(d => d.unified_flow === "CREATE_FLOW");

// سجل الأرقام لمعالجة التكرار داخل نفس الباتش
const processedPhones = new Set();

const leadsBodies = [];     // أجسام الـ leads التي سترسل إلى API
const requestMeta = [];     // ماب: request_id -> meta (هنحتاجه بعد الـ HTTP)

for (const d of inputItems) {
  // اختر سجل أساس تُبنى عليه البيانات
  const records = Array.isArray(d.all_records) ? d.all_records : [d];
  const base = records[0] || {};

  // استخرج تليفون أساسي للتكرار المحلي
  const phonesRaw = [
    base.phone_1, base.phone_2, base.phone_3, base.phone_4, base.phone_5,
    ...(Array.isArray(base.phone_values) ? base.phone_values : []),
    base.contact_phone
  ].filter(isNonEmpty);

  if (!phonesRaw.length) continue;

  const primaryPhone = normalizePhone(phonesRaw[0]);
  if (processedPhones.has(primaryPhone)) {
    // Duplicate in this batch — تخطي
    continue;
  }
  processedPhones.add(primaryPhone);

  // أسماء
  const fullNameCandidate =
    base.full_name ||
    base.contact_name ||
    `${toStr(base.first_name)} ${toStr(base.last_name)}`.trim();

  let firstName = base.first_name || "";
  let lastName  = base.last_name || "";

  if ((!firstName || !lastName) && fullNameCandidate) {
    const parts = fullNameCandidate.split(/\s+/);
    firstName = firstName || (parts[0] || "");
    lastName  = lastName  || (parts.slice(1).join(" ") || "");
  }

  const finalFullName = fullNameCandidate || `${firstName} ${lastName}`.trim() || "Unknown Contact";

  // اسم الشركة
  const companyName =
    base.company_name || base.companyName ||
    (base.folder_name || base.folderName || "").replace(/^TAX\s+/i, "").trim() ||
    "Unknown Company";

  // اجمع حتى 5 هواتف وإيميلات
  const allPhones = uniq(phonesRaw.map(normalizePhone)).slice(0, 5);

  const emailsRaw = [
    base.email_1, base.email_2, base.email_3, base.email_4, base.email_5,
    ...(Array.isArray(base.email_values) ? base.email_values : []),
    base.contact_email
  ].filter(isNonEmpty);

  const allEmails = uniq(
    emailsRaw.map(e => String(e).toLowerCase()).filter(e => e.includes("@"))
  ).slice(0, 5);

  // custom_fields_values للكونتاكت
  const contactCustomFields = [];
  if (allPhones.length) {
    contactCustomFields.push({
      field_code: "PHONE",
      values: allPhones.map(p => ({ value: p, enum_code: "WORK" })),
    });
  }
  if (allEmails.length) {
    contactCustomFields.push({
      field_code: "EMAIL",
      values: allEmails.map(e => ({ value: e, enum_code: "WORK" })),
    });
  }

  // مهم جدًا: request_id لربط الرد بالعنصر الأصلي
  const rid =
    d.correlation_key
      ? `rid::${d.correlation_key}`
      : `rid::${primaryPhone}`;

  // جسم الليد (وفق /leads/complex)
  const leadBody = {
    request_id: rid, // Kommo سيرجعه لنا في الاستجابة
    name: finalFullName,
    pipeline_id: PIPELINE_ID,
    status_id: STATUS_ID,
    responsible_user_id: RESPONSIBLE_USER_ID,
    created_by: RESPONSIBLE_USER_ID,
    _embedded: {
      tags: FIXED_TAGS,
      companies: [{ name: companyName }],
      contacts: [{
        first_name: firstName || "Unknown",
        last_name: lastName || "",
        name: finalFullName,
        ...(contactCustomFields.length ? { custom_fields_values: contactCustomFields } : {})
      }]
    }
  };

  leadsBodies.push(leadBody);

  // خزّن الميتا علشان نستخدمه بعد الـ HTTP في نود الكود التالية
  requestMeta.push({
    request_id: rid,
    correlation_key: d.correlation_key || null,
    mode: d.mode || null,                // CREATE أو HYBRID
    sheet_row: d.sheet_row || null,      // هنحدّث new_*_id لاحقًا
    old_ids: d.old_ids || null,          // لو HYBRID
    origin: d.origin || null,            // بيانات أولية
  });
}

// تقسيم دفعات بحد أقصى 50
const chunkSize = 50;
const chunks = [];
for (let i = 0; i < leadsBodies.length; i += chunkSize) {
  chunks.push(leadsBodies.slice(i, i + chunkSize));
}

// لو مفيش ولا ليد للإنشاء، رجّع عنصر واحد للإبلاغ
if (!chunks.length) {
  return [{
    json: {
      info: "No leads to create (CREATE_FLOW empty or all duplicates by phone)",
      total_input: inputItems.length,
      leads_prepared: 0
    }
  }];
}

// أعدّ عناصر خروج متعددة — كل عنصر = دفعة واحدة للـ HTTP
return chunks.map((batch, idx) => ({
  json: {
    method: "POST",
    url: `https://${SUBDOMAIN}.kommo.com/api/v4/leads/complex`,
    payload: batch,               // Array of lead bodies
    batch_index: idx,
    batch_size: batch.length,
    total_batches: chunks.length,
    // مرّر الميتا كلها مرة واحدة — النود التالية هتربط بالـ request_id
    request_meta: requestMeta
  }
}));

// ---- Helpers ----
function normPhone(p) {
  if (!p) return null;
  let s = String(p).trim();
  s = s.replace(/^rid::/i, "");
  s = s.split(",")[0].trim();
  s = s.replace(/[()\-\s]/g, "");
  if (s.startsWith("00")) s = "+" + s.slice(2);
  if (!s.startsWith("+") && /^\d+$/.test(s)) s = "+" + s;
  return s || null;
}
function toArrayMaybe(v) { return v == null ? [] : (Array.isArray(v) ? v : [v]); }

// ---- Normalize ----
const srcItems = (items.length === 1 && Array.isArray(items[0]?.json))
  ? items[0].json.map(x => ({ json: x }))
  : items;

const branchA = [], branchB = [];
for (const it of srcItems) {
  const d = it.json || {};
  const hasKommoIds = ("id" in d) || ("contact_id" in d) || ("company_id" in d);
  const hasBatchHints = ("folderName" in d) || ("Company type" in d) || ("companyName" in d) || ("batchDate" in d);
  const reqIds = toArrayMaybe(d.request_id);
  const hasReq = reqIds.length > 0 || typeof d.request_id === "string";
  if (hasKommoIds && hasReq) branchA.push(d);
  else if (hasBatchHints) branchB.push(d);
  else (d.contact_phone ? branchB : branchA).push(d);
}

// ---- Build map ----
const createdMap = new Map();
for (const r of branchA) {
  const ridRaw = toArrayMaybe(r.request_id)[0] ?? r.request_id ?? null;
  const ridPhone = normPhone(ridRaw) || normPhone(r.contact_phone || r.phone);
  if (!ridPhone) continue;
  createdMap.set(ridPhone, {
    new_lead_id: r.id ?? null,
    new_contact_id: r.contact_id ?? null,
    new_company_id: r.company_id ?? null,
    merged: !!r.merged,
  });
}

// ---- Helper: infer type + icon ----
function inferStatus({ routing, status_code, message_ar, hasCreatedIds }) {
  const msg = (message_ar || "").toLowerCase();
  let type = "UNKNOWN";
  let icon = "⚪";

  if (routing === "SKIP_COMPLETE" || /قيد موجود|existing/.test(msg)) {
    type = "EXISTING"; icon = "✅";
  } else if (/مكرر|duplicate/.test(msg)) {
    type = "DUPLICATE"; icon = "🔴";
  } else if (routing === "CREATE_NEW" || status_code === "RECREATE" || /إعادة إنشاء|hybrid|recreate/i.test(msg)) {
    type = "NEW_OR_RECREATE"; icon = "🟡";
  } else if (hasCreatedIds) {
    type = "CREATED"; icon = "🟢";
  }

  return { type, icon, label: `${type} ${icon}` };
}

// ---- Compose output ----
const out = [];
const batchSize = branchB.length;

branchB.forEach((row, idx) => {
  const phone = normPhone(row.contact_phone);
  if (!phone) return;

  const hit = createdMap.get(phone) || {
    new_lead_id: null, new_contact_id: null, new_company_id: null, merged: false
  };

  const companyType = (row["Company type"] || "").toString().trim().toUpperCase();
  const mode = companyType || "UNKNOWN";
  const status_code = (row.status || "").toString().trim() || null;
  const routing = (row.routing || status_code || "").toString().trim() || "UNKNOWN";
  const message_ar = row.message_ar || null;
  const folder_name  = row.folderName || row.folder_name || null;
  const folder_Id    = row.folderId   || row.folder_Id   || null;
  const company_name = row.companyName || row.company_name || null;
  const contact_name = row.full_name || [row.contact_first, row.contact_last].filter(Boolean).join(" ") || null;
  const hasCreatedIds = !!(hit.new_lead_id || hit.new_contact_id || hit.new_company_id);

  // 👇 تحديد النوع والعلامة معًا في خطوة واحدة
  const { type: status_type, icon: status_icon, label: status_label } =
    inferStatus({ routing, status_code, message_ar, hasCreatedIds });

  const request_id = `rid::${phone}`;

  out.push({
    json: {
      request_id,
      correlation_key: `${folder_name || company_name || "N/A"}::${phone}`,
      mode,
      status_code,
      status_type: status_label,   // 🟢🟡🔴✅ في سطر واحد
      status_icon,
      message_ar,                  // الرسالة العربية الأصلية
      merged: !!hit.merged,

      new_lead_id: hit.new_lead_id,
      new_contact_id: hit.new_contact_id,
      new_company_id: hit.new_company_id,

      old_ids: {
