        mode,
        routing,
        status_code,
        status_type: status_label,
        status_icon,
        message_ar,
        unified_flow: row.unified_flow || null,
        folder_name,
        old_lead_id: row.lead_id ?? null,
        old_contact_id: row.contact_id ?? null,
        old_company_id: row.company_id ?? null,
        new_lead_id: hit.new_lead_id,
        new_contact_id: hit.new_contact_id,
        new_company_id: hit.new_company_id,
        primary_query_type: "phone",
        primary_query_value: phone,
        note: row.message || "",
        batch_date: row.batchDate || null,
        batch_time: row.batchtime || null,
        result: hasCreatedIds ? "CREATED" : "NOT_FOUND",
        batch_index: idx + 1,
        batch_size: batchSize,
      }
    }
  });
});

return out;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
