const INPUT_ITEMS = $input.all();

// ---------- Helpers ----------
const toStr = v => (v == null ? "" : String(v)).trim();
const isNonEmpty = v => v != null && String(v).trim() !== "";
const firstOf = (...vals) => {
  for (const v of vals) {
    if (Array.isArray(v) && v.length) {
      const f = v.find(isNonEmpty);
      if (isNonEmpty(f)) return toStr(f);
    } else if (isNonEmpty(v)) {
      return toStr(v);
    }
  }
  return "";
};
const toMonth = (d) => {
  const s = toStr(d);
  // expect YYYY-MM-DD (from origin.batch_date / sheet_row.batch_date)
  if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return "";
  return s.slice(0, 7);
};
const splitName = (full, first, last) => {
  let fn = toStr(first);
  let ln = toStr(last);
  let fullName = toStr(full);
  if (!fn && !ln && fullName) {
    const parts = fullName.split(/\s+/).filter(Boolean);
    fn = parts[0] || "";
    ln = parts.slice(1).join(" ") || "";
  }
  const finalFull = fullName || [fn, ln].filter(Boolean).join(" ");
  return { first: fn, last: ln, full: finalFull || "" };
};

// ---------- Normalize source (handle single item that wraps an array) ----------
const srcItems = (INPUT_ITEMS.length === 1 && Array.isArray(INPUT_ITEMS[0]?.json))
  ? INPUT_ITEMS[0].json.map(x => ({ json: x }))
  : INPUT_ITEMS;

// ---------- Build rows ----------
const rows = [];

for (const it of srcItems) {
