    origin.folder_name
  );
  const folderId = firstOf(
    origin.folder_Id,
    d.folder_Id
  );

  // Dates
  const batchDate = firstOf(origin.batch_date, sheetRow.batch_date);
  const batchTime = firstOf(origin.batch_time, sheetRow.batch_time);
  const month     = toMonth(batchDate);

  // Mode / Company type
  const companyType = firstOf(d.mode, sheetRow.mode, d["Company type"]);

