  const status_type = firstOf(d.status_type, sheetRow.status_type);
  const status_icon = firstOf(d.status_icon, sheetRow.status_icon);
  const message_ar  = firstOf(d.message_ar, sheetRow.message_ar);

  // Generic message + result (optional)
  const message = firstOf(d.sheet_note, sheetRow.note, d.message);
  const status  = firstOf(sheetRow.result, d.action, d.status); // أبقيه لو محتاج عمود مختصر

  // Tags (قد لا توجد في هذا السيناريو)
  const tagsArr   = Array.isArray(base.tags) ? base.tags : [];
  const tagIdsArr = Array.isArray(base.tag_ids) ? base.tag_ids : [];
  const tagsStr   = tagsArr.join(", ");
  const tagIdsStr = tagIdsArr.join(", ");

  // Tax Type (افتراضي)
  const taxType = tagsArr.includes("MonthlyTax") ? "MonthlyTax" : "";

  // Document (غير متوفر)
  const documentId = "";
  const documentName = "";

  rows.push({
    json: {
      // الأعمدة بالترتيب المقترح للشيت
      "batchDate":       batchDate || "",
      "batchtime":       batchTime || "",
      "Company type":    companyType || "",
      "folderName":      folderName || "",
      "folderId":        folderId || "",
      "documentId":      documentId,
      "documentName":    documentName,
      "companyName":     companyName || "",
      "month":           month || "",
      "taxType":         taxType,
      "message":         message,         // ملاحظات عامة إن وجدت
      "message_ar":      message_ar,      // الرسالة العربية (جديد/مكرر/موجود فعلاً)
      "status":          status,          // result/action كقيمة مختصرة إن احتجتها
      "status_code":     status_code,     // RECREATE / SKIP_COMPLETE / ...
      "status_type":     status_type,     // يحتوي النص + الإيموجي حسب الإنبت
      "status_icon":     status_icon,     // الإيموجي منفصل لو تحب عمود أيقونة فقط
      "contact_first":   nameInfo.first,
      "contact_last":    nameInfo.last,
      "full_name":       nameInfo.full,
      "contact_phone":   phone,
      "contact_email":   email,
      "leadId":          String(leadId || ""),
      "contactId":       String(contactId || ""),
      "companyId":       String(companyId || ""),
      "tags":            tagsStr,
      "tagıd":           tagIdsStr
    }
  });
}

return rows;

