/** يحاول استخراج IDs من message_ar كـ fallback */
function parseIdsFromMessageAr(msg) {
  const txt = toStr(msg);
  const lead   = (txt.match(/Lead:\s*(\d+)/i)    || [])[1] || "";
  const contact= (txt.match(/Contact:\s*(\d+)/i) || [])[1] || "";
  const company= (txt.match(/Company:\s*(\d+)/i) || [])[1] || "";
  return { lead_id: lead, contact_id: contact, company_id: company };
}

/** يحاول تحليل duplicate_ids أيًا كان شكلها (JSON/قائمة/أقواس مربعة) */
function parseDuplicateIds(raw) {
  const s = toStr(raw).trim();
  if (!s) return [];

  // جرّب JSON أو Array نصّي
  try {
    const j = JSON.parse(s);
    if (Array.isArray(j)) return j.map(String);
    if (typeof j === "object") {
      // لو كائن فيه مفاتيح متعددة
      return Object.values(j).flat().map(String);
    }
  } catch (_) { /* ignore */ }

  // جرّب تنضيف الأقواس والفواصل
  const cleaned = s.replace(/[\[\]\s]/g, "");
  if (!cleaned) return [];
  return cleaned.split(",").filter(Boolean);
}

/** يدمج ويُميّز العناصر */
function uniq(arr) {
  return Array.from(new Set(arr.filter(Boolean).map(String)));
}

/**********************
 * 2) Read input
 **********************/
const inputItems = $input.all().map(i => i.json);

// سنستخدم الهاتف لمكافحة التكرار داخل نفس الدفعة
const seenPhones = new Set();
const out = [];

/**********************
 * 3) Process rows
 **********************/
for (const row of inputItems) {
  // --- تطبيع وتجهيز الحقول الأساسية ---
  const phone = normPhone(row.contact_phone);
  const fullName = toStr(row.full_name || [row.contact_first, row.contact_last].filter(Boolean).join(" "));
  const company  = toStr(row.companyName || row.company_name);

  // حالة وشرح
  const status   = toStr(row.status);        // SKIP_COMPLETE | RECREATE | CREATE_NEW | ...
  const icon     = toStr(row.status_icon);   // 🟢 / 🟡 / ✅  (اختياري)
  const msgAr    = toStr(row.message_ar);

  // --- IDs منفصلة: من الحقول المباشرة أو fallback من message_ar ---
  const idsFromMsg = parseIdsFromMessageAr(msgAr);
  const lead_id     = toStr(row.leadId || row.lead_id || idsFromMsg.lead_id);
  const contact_id  = toStr(row.contact_id || idsFromMsg.contact_id);
  const company_id  = toStr(row.company_id || idsFromMsg.company_id);

  // --- التكرار المُبلّغ من النظام (cross-batch / in-system) ---
  const duplicateType = toStr(row.duplicate_type);
  const duplicateIdsRaw= toStr(row.duplicate_ids);
  const duplicateIdsParsed = parseDuplicateIds(duplicateIdsRaw);
  const duplicateInSystem = duplicateType || duplicateIdsParsed.length > 0;

  // --- حالة الاكتمال المطلوبة (٣ عناصر) ---
  const missing = [];
  if (!nonEmpty(phone))    missing.push("phone");
  if (!nonEmpty(fullName)) missing.push("full_name");
  if (!nonEmpty(company))  missing.push("company");

  // --- منع التكرار داخل نفس الدفعة (حسب الهاتف بعد التطبيع) ---
  let blockedByBatchDup = false;
  if (!missing.length) {
    if (seenPhones.has(phone)) blockedByBatchDup = true;
    else seenPhones.add(phone);
  }

  // --- نلغي الـ Hybrid تمامًا (RECREATE => BLOCKED) ---
  const isHybrid = status.toUpperCase() === "RECREATE";

  // --- تحديد المسار والسبب واللون ---
  let route = "";
  let reason = "";
  let color = "";   // hex
  let emoji = icon || "ℹ️";

  if (missing.length > 0) {
    // BLOCKED بسبب نقص البيانات مع تمرير أي IDs معروفة
    route  = "BLOCKED";
    reason = `Missing required: ${missing.join(", ")}`;
    color  = "#f59e0b"; // Amber
    emoji  = "🟠";
  } else if (blockedByBatchDup) {
    route  = "BLOCKED";
    reason = "Duplicate in the same batch (same phone).";
    color  = "#dc2626"; // Red
    emoji  = "🔴";
  } else if (duplicateInSystem || isHybrid) {
    // أي تكرار أو RECREATE => BLOCKED (لا إنشاء جديد)
    route  = "BLOCKED";
    const idsNote = duplicateIdsParsed.length
      ? ` [ids: ${duplicateIdsParsed.join(", ")}]`
      : "";
    reason = isHybrid
      ? `Hybrid (RECREATE) disabled by policy; handle merge/delete first.${idsNote}`
      : `Duplicate in system${duplicateType ? ` (${duplicateType})` : ""}${idsNote}`;
    color  = "#dc2626"; // Red
    emoji  = "🔴";
  } else {
    // مكتمل وغير مكرر
    // PASS_EXISTING: بيانات مكتملة + مسجلة بالفعل (اعتمدنا وجود lead_id + SKIP_COMPLETE)
    const isExisting = status.toUpperCase() === "SKIP_COMPLETE" && nonEmpty(lead_id);
    if (isExisting) {
      route = "PASS_EXISTING";
      color = "#2563eb"; // Blue
      emoji = "🔵";
    } else {
      // CREATE: مكتمل وغير مسجل وغير مكرر
      route = "CREATE";
      color = "#16a34a"; // Green
      emoji = "🟢";
    }
  }

  // سطر حالة موحد
  const status_line = [emoji, status || "-", msgAr || ""].filter(Boolean).join(" | ");

  // تجميع كل IDs المفيدة للعرض/المعالجة
  const ids_all = uniq([
    lead_id, contact_id, company_id,
    ...duplicateIdsParsed
  ]);

  out.push({
    json: {
      ...row,

      // 1) IDs منفصلة ودائمًا موجودة (حتى لو فاضية)
      lead_id,
      contact_id,
      company_id,

      // 2) معلومات التكرار إن وجدت
      duplicate_type: duplicateType || "",
      duplicate_ids_raw: duplicateIdsRaw || "",
      duplicate_ids_list: duplicateIdsParsed,

      // 3) حقول القرار للـ Switch
      phone_normalized: phone || "",
      status_line,
      route,                       // PASS_EXISTING | CREATE | BLOCKED
      error_reason: route === "BLOCKED" ? reason : "",
      status_color: color,         // تلوين واضح للحالة
      status_emoji: emoji,

      // 4) مفيد للتوثيق/العرض
      ids_all                      // كل المعرّفات المتاحة (مجتمعة)
    }
  });
}

/**********************
 * 4) Return
 **********************/
return out;
